import { jsPDF } from 'jspdf';
import QRCode from 'qrcode';
import JsBarcode from 'jsbarcode';
import { Manifest } from '../types';

export const generateManifestPDF = async (manifest: Manifest, isPreview: boolean = false): Promise<string | null> => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4',
  });

  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();

  for (let i = 1; i <= manifest.palletsCount; i++) {
    if (i > 1) doc.addPage();

    // Border
    doc.setLineWidth(0.5);
    doc.rect(10, 10, pageWidth - 20, pageHeight - 20);

    // Header - Manifest Number
    doc.setFontSize(10);
    doc.text('MANIFESTO DE CONFERÊNCIA', pageWidth / 2, 20, { align: 'center' });

    doc.setFontSize(48);
    doc.setFont('helvetica', 'bold');
    doc.text(manifest.manifestNumber, pageWidth / 2, 40, { align: 'center' });

    // Barcode
    const canvas = document.createElement('canvas');
    JsBarcode(canvas, manifest.manifestNumber, {
      format: 'CODE128',
      width: 2,
      height: 60,
      displayValue: false
    });
    const barcodeImg = canvas.toDataURL('image/png');
    doc.addImage(barcodeImg, 'PNG', (pageWidth - 100) / 2, 45, 100, 20);

    // Separator
    doc.setLineWidth(0.2);
    doc.line(15, 70, pageWidth - 15, 70);

    // Destination
    doc.setFontSize(14);
    doc.setFont('helvetica', 'normal');
    doc.text('DESTINO:', 20, 85);
    doc.setFontSize(28);
    doc.setFont('helvetica', 'bold');
    doc.text(manifest.branchName, 20, 98);

    // CD Info
    doc.setFontSize(12);
    doc.setFont('helvetica', 'normal');
    doc.text(`ORIGEM (CD): ${manifest.cdName} (${manifest.cdId})`, 20, 110);

    // Details Grid
    doc.setFontSize(12);
    doc.text(`DATA: ${new Date(manifest.conferenceDate).toLocaleDateString('pt-BR')}`, 20, 125);
    doc.text(`CONFERENTE: ${manifest.checkerName}`, 20, 132);

    // Pallet Sequence (LARGE)
    doc.setFontSize(14);
    doc.text('PALETE:', pageWidth - 60, 125);
    doc.setFontSize(42);
    doc.setFont('helvetica', 'bold');
    doc.text(`${i}/${manifest.palletsCount}`, pageWidth - 60, 145);

    // Orders List
    doc.setFontSize(12);
    doc.setFont('helvetica', 'bold');
    doc.text('PEDIDOS NESTE MANIFESTO:', 20, 160);
    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    const splitOrders = doc.splitTextToSize(manifest.orders, pageWidth - 40);
    doc.text(splitOrders, 20, 168);

    // QR Code
    const qrContent = JSON.stringify({
      m: manifest.manifestNumber,
      f: manifest.branchName,
      c: manifest.checkerName,
      p: `${i}/${manifest.palletsCount}`
    });
    const qrDataUrl = await QRCode.toDataURL(qrContent);
    doc.addImage(qrDataUrl, 'PNG', pageWidth - 50, 160, 30, 30);

    // Signature / Label Area
    doc.setLineWidth(0.1);
    doc.setLineDashPattern([2, 2], 0);
    doc.rect(20, pageHeight - 60, pageWidth - 40, 40);
    doc.setFontSize(9);
    doc.text('ESPAÇO RESERVADO PARA ASSINATURA OU ETIQUETA ADICIONAL', pageWidth / 2, pageHeight - 40, { align: 'center' });
    doc.setLineDashPattern([], 0);

    // Footer
    doc.setFontSize(8);
    doc.text(`Gerado em: ${new Date().toLocaleString('pt-BR')} | LogiLabel Pro v1.0`, 20, pageHeight - 15);
  }

  if (isPreview) {
    return doc.output('bloburl').toString();
  } else {
    doc.save(`Manifesto_${manifest.manifestNumber}_Etiquetas.pdf`);
    return null;
  }
};

import React from 'react';
import { 
  LayoutDashboard, 
  PlusCircle, 
  History, 
  Settings, 
  LogOut, 
  Truck,
  Users,
  Building2,
  PackageCheck
} from 'lucide-react';
import { UserProfile } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  user: UserProfile;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  onLogout: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, user, activeTab, setActiveTab, onLogout }) => {
  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard, roles: ['ADMIN', 'CONFERENTE'] },
    { id: 'generate', label: 'Gerar Etiquetas', icon: PlusCircle, roles: ['ADMIN', 'CONFERENTE'] },
    { id: 'history', label: 'Histórico', icon: History, roles: ['ADMIN', 'CONFERENTE'] },
    { id: 'checkers', label: 'Conferentes', icon: Users, roles: ['ADMIN'] },
    { id: 'branches', label: 'Filiais', icon: Building2, roles: ['ADMIN'] },
    { id: 'cds', label: 'Centros (CD)', icon: Truck, roles: ['ADMIN'] },
  ];

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 text-slate-300 flex flex-col no-print">
        <div className="p-6 flex items-center gap-3 border-b border-slate-800">
          <PackageCheck className="text-blue-500 w-8 h-8" />
          <span className="font-bold text-xl text-white tracking-tight">LogiLabel<span className="text-blue-500">Pro</span></span>
        </div>

        <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
          {menuItems.map((item) => {
            if (!item.roles.includes(user.role)) return null;
            const Icon = item.icon;
            const isActive = activeTab === item.id;

            return (
              <button
                key={item.id}
                onClick={() => setActiveTab(item.id)}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
                  isActive 
                    ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' 
                    : 'hover:bg-slate-800 hover:text-white'
                }`}
              >
                <Icon size={20} />
                <span className="font-medium text-sm">{item.label}</span>
              </button>
            );
          })}
        </nav>

        <div className="p-4 border-t border-slate-800 space-y-4">
          <div className="px-4 py-2 bg-slate-800/50 rounded-lg">
            <p className="text-xs text-slate-500 uppercase font-bold tracking-wider">Usuário</p>
            <p className="text-sm font-semibold text-white truncate">{user.name}</p>
            <p className="text-[10px] text-blue-400 font-bold">{user.role}</p>
          </div>
          <button 
            onClick={onLogout}
            className="w-full flex items-center gap-3 px-4 py-3 text-slate-400 hover:text-red-400 hover:bg-red-500/10 rounded-lg transition-colors"
          >
            <LogOut size={20} />
            <span className="font-medium text-sm">Sair do Sistema</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-8 no-print">
          <h1 className="text-xl font-bold text-slate-800">
            {menuItems.find(i => i.id === activeTab)?.label || 'Sistema'}
          </h1>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="text-xs text-slate-500">{new Date().toLocaleDateString('pt-BR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8">
          {children}
        </div>
      </main>
    </div>
  );
};

export default Layout;

import React from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { FileText, Layers, TrendingUp, Calendar } from 'lucide-react';
import { Manifest } from '../types';

interface DashboardProps {
  manifests: Manifest[];
}

const Dashboard: React.FC<DashboardProps> = ({ manifests }) => {
  const today = new Date().toISOString().split('T')[0];
  const manifestsToday = manifests.filter(m => m.createdAt.startsWith(today));
  const palletsToday = manifestsToday.reduce((acc, m) => acc + m.palletsCount, 0);

  // Calculate daily volume for the last 7 days
  const dailyData = Array.from({ length: 7 }).map((_, i) => {
    const d = new Date();
    d.setDate(d.getDate() - (6 - i));
    const dateStr = d.toISOString().split('T')[0];
    const count = manifests.filter(m => m.createdAt.startsWith(dateStr)).length;
    return {
      name: d.toLocaleDateString('pt-BR', { weekday: 'short' }),
      date: dateStr,
      count
    };
  });

  const stats = [
    { label: 'Manifestos (Hoje)', value: manifestsToday.length, icon: FileText, color: 'bg-blue-500' },
    { label: 'Paletes (Hoje)', value: palletsToday, icon: Layers, iconColor: 'text-emerald-500', color: 'bg-emerald-500' },
    { label: 'Total de Manifestos', value: manifests.length, icon: TrendingUp, color: 'bg-indigo-500' },
    { label: 'Volume Semanal', value: dailyData.reduce((a, b) => a + b.count, 0), icon: Calendar, color: 'bg-amber-500' },
  ];

  return (
    <div className="space-y-8">
      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, idx) => {
          const Icon = stat.icon;
          return (
            <div key={idx} className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex items-center gap-5">
              <div className={`${stat.color} p-3 rounded-lg text-white shadow-lg shadow-${stat.color.split('-')[1]}-200`}>
                <Icon size={24} />
              </div>
              <div>
                <p className="text-slate-500 text-sm font-medium">{stat.label}</p>
                <h3 className="text-2xl font-bold text-slate-800">{stat.value}</h3>
              </div>
            </div>
          );
        })}
      </div>

      {/* Chart Section */}
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-lg font-bold text-slate-800 mb-6">Volume de Manifestos nos Últimos 7 Dias</h3>
        <div className="h-[300px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={dailyData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis 
                dataKey="name" 
                axisLine={false} 
                tickLine={false} 
                tick={{ fill: '#64748b', fontSize: 12 }}
                dy={10}
              />
              <YAxis 
                axisLine={false} 
                tickLine={false} 
                tick={{ fill: '#64748b', fontSize: 12 }}
              />
              <Tooltip 
                cursor={{ fill: '#f8fafc' }}
                contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
              />
              <Bar dataKey="count" radius={[4, 4, 0, 0]} barSize={40}>
                {dailyData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={index === 6 ? '#2563eb' : '#94a3b8'} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Recent History Preview */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center">
          <h3 className="text-lg font-bold text-slate-800">Últimos Manifestos Gerados</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-xs uppercase font-bold tracking-wider">
              <tr>
                <th className="px-6 py-4">Manifesto</th>
                <th className="px-6 py-4">Destino</th>
                <th className="px-6 py-4">Conferente</th>
                <th className="px-6 py-4">Paletes</th>
                <th className="px-6 py-4">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 text-sm">
              {manifests.slice(0, 5).map((m) => (
                <tr key={m.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 font-bold text-slate-700">{m.manifestNumber}</td>
                  <td className="px-6 py-4 text-slate-600">{m.branchName}</td>
                  <td className="px-6 py-4 text-slate-600">{m.checkerName}</td>
                  <td className="px-6 py-4 text-slate-600 font-medium">{m.palletsCount} paletes</td>
                  <td className="px-6 py-4">
                    <span className="px-2 py-1 bg-emerald-100 text-emerald-700 rounded-full text-[10px] font-bold">GERADO</span>
                  </td>
                </tr>
              ))}
              {manifests.length === 0 && (
                <tr>
                  <td colSpan={5} className="px-6 py-10 text-center text-slate-400">Nenhum manifesto registrado ainda.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { 
  FileDown, 
  Eye, 
  Printer, 
  AlertCircle,
  X,
  Loader2,
  CheckCircle2
} from 'lucide-react';
import { 
  Checker, 
  Branch, 
  DistributionCenter, 
  Manifest 
} from '../types';
import { generateManifestPDF } from '../services/pdfGenerator';

interface ManifestFormProps {
  checkers: Checker[];
  branches: Branch[];
  cds: DistributionCenter[];
  onSave: (manifest: Manifest) => void;
  currentUser: { name: string; uid: string };
}

const ManifestForm: React.FC<ManifestFormProps> = ({ 
  checkers, 
  branches, 
  cds, 
  onSave,
  currentUser
}) => {
  const [formData, setFormData] = useState({
    manifestNumber: '',
    orders: '',
    conferenceDate: new Date().toISOString().split('T')[0],
    cdId: cds[0]?.id || '',
    branchId: '',
    checkerId: '',
    palletsCount: 1
  });

  const [isPreviewing, setIsPreviewing] = useState(false);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const activeCheckers = checkers.filter(c => c.status === 'ATIVO');
  const activeBranches = branches.filter(b => b.status === 'ATIVO');

  const validate = () => {
    if (!formData.manifestNumber) return "Número do manifesto é obrigatório";
    if (!formData.orders) return "Lista de pedidos é obrigatória";
    if (!formData.branchId) return "Selecione uma filial de destino";
    if (!formData.checkerId) return "Selecione um conferente";
    if (formData.palletsCount < 1) return "Quantidade de paletes deve ser pelo menos 1";
    return null;
  };

  const constructManifest = (): Manifest => {
    const cd = cds.find(c => c.id === formData.cdId);
    const branch = branches.find(b => b.id === formData.branchId);
    const checker = checkers.find(c => c.id === formData.checkerId);

    return {
      id: Math.random().toString(36).substr(2, 9),
      ...formData,
      createdAt: new Date().toISOString(),
      createdBy: currentUser.name,
      cdName: cd?.name || '',
      branchName: branch?.name || '',
      checkerName: checker?.name || ''
    };
  };

  const handlePreview = async () => {
    const err = validate();
    if (err) {
      setError(err);
      return;
    }
    setError(null);
    setIsGenerating(true);
    try {
      const manifest = constructManifest();
      const url = await generateManifestPDF(manifest, true);
      setPreviewUrl(url);
      setIsPreviewing(true);
    } catch (e) {
      setError("Erro ao gerar pré-visualização.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = async () => {
    const err = validate();
    if (err) {
      setError(err);
      return;
    }
    setError(null);
    setIsGenerating(true);
    try {
      const manifest = constructManifest();
      await generateManifestPDF(manifest, false);
      onSave(manifest);
      // Reset form
      setFormData({
        ...formData,
        manifestNumber: '',
        orders: '',
        palletsCount: 1
      });
    } catch (e) {
      setError("Erro ao salvar manifesto.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm space-y-6">
        <div className="flex items-center gap-3 border-b border-slate-100 pb-4">
          <CheckCircle2 className="text-blue-600" />
          <h2 className="text-xl font-bold text-slate-800">Nova Conferência de Paletes</h2>
        </div>

        {error && (
          <div className="bg-red-50 border-l-4 border-red-500 p-4 flex items-center gap-3 text-red-700 text-sm">
            <AlertCircle size={18} />
            {error}
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Número do Manifesto *</label>
              <input
                type="text"
                placeholder="Ex: 559082"
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                value={formData.manifestNumber}
                onChange={e => setFormData({ ...formData, manifestNumber: e.target.value.toUpperCase() })}
              />
            </div>

            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Centro de Distribuição *</label>
              <select
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                value={formData.cdId}
                onChange={e => setFormData({ ...formData, cdId: e.target.value })}
              >
                {cds.map(cd => <option key={cd.id} value={cd.id}>{cd.name} ({cd.code})</option>)}
              </select>
            </div>

            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Filial de Destino *</label>
              <select
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                value={formData.branchId}
                onChange={e => setFormData({ ...formData, branchId: e.target.value })}
              >
                <option value="">Selecione a Filial...</option>
                {activeBranches.map(b => <option key={b.id} value={b.id}>{b.name} ({b.code})</option>)}
              </select>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-1">Data Conferência *</label>
                <input
                  type="date"
                  className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  value={formData.conferenceDate}
                  onChange={e => setFormData({ ...formData, conferenceDate: e.target.value })}
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-1">Qtd. de Paletes *</label>
                <input
                  type="number"
                  min="1"
                  max="50"
                  className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  value={formData.palletsCount}
                  onChange={e => setFormData({ ...formData, palletsCount: parseInt(e.target.value) || 1 })}
                />
              </div>
            </div>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Conferente Responsável *</label>
              <select
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                value={formData.checkerId}
                onChange={e => setFormData({ ...formData, checkerId: e.target.value })}
              >
                <option value="">Selecione o Conferente...</option>
                {activeCheckers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
            </div>

            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Lista de Pedidos (NFs / Cargas) *</label>
              <textarea
                rows={6}
                placeholder="Insira os números dos pedidos separados por vírgula ou um por linha..."
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all resize-none"
                value={formData.orders}
                onChange={e => setFormData({ ...formData, orders: e.target.value })}
              />
            </div>
          </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4 pt-6 border-t border-slate-100">
          <button
            onClick={handlePreview}
            disabled={isGenerating}
            className="flex-1 flex items-center justify-center gap-2 px-6 py-3 bg-slate-100 text-slate-700 font-bold rounded-lg hover:bg-slate-200 transition-colors disabled:opacity-50"
          >
            {isGenerating ? <Loader2 className="animate-spin" /> : <Eye size={20} />}
            Visualizar PDF
          </button>
          <button
            onClick={handleDownload}
            disabled={isGenerating}
            className="flex-1 flex items-center justify-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-lg hover:bg-blue-700 shadow-lg shadow-blue-200 transition-all disabled:opacity-50"
          >
            {isGenerating ? <Loader2 className="animate-spin" /> : <FileDown size={20} />}
            Gerar e Baixar Etiquetas
          </button>
        </div>
      </div>

      {/* Preview Modal */}
      {isPreviewing && previewUrl && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-5xl h-[90vh] rounded-2xl flex flex-col overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <h3 className="font-bold text-slate-800 flex items-center gap-2">
                <Eye size={18} className="text-blue-600" />
                Pré-visualização do PDF
              </h3>
              <button 
                onClick={() => setIsPreviewing(false)}
                className="p-2 hover:bg-red-100 text-slate-400 hover:text-red-600 rounded-full transition-colors"
              >
                <X size={24} />
              </button>
            </div>
            <div className="flex-1 bg-slate-800">
              <iframe 
                src={previewUrl} 
                className="w-full h-full border-none"
                title="PDF Preview"
              />
            </div>
            <div className="p-4 bg-white border-t border-slate-100 flex justify-end gap-3">
              <button 
                onClick={() => setIsPreviewing(false)}
                className="px-6 py-2 bg-slate-200 text-slate-700 rounded-lg font-bold"
              >
                Fechar
              </button>
              <button 
                onClick={() => {
                  const link = document.createElement('a');
                  link.href = previewUrl;
                  link.download = `Preview_Manifesto_${formData.manifestNumber}.pdf`;
                  link.click();
                }}
                className="px-6 py-2 bg-blue-600 text-white rounded-lg font-bold flex items-center gap-2"
              >
                <Printer size={18} />
                Baixar Prévia
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

