                              const newList = branches.filter(item => item.id !== b.id);
                              setBranches(newList);
                              localStorage.setItem('logi_branches', JSON.stringify(newList));
                            }}
                            className="text-slate-400 hover:text-red-600 p-1"
                          >
                            <Trash2 size={16} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        );

      case 'cds':
        return (
          <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm max-w-2xl">
             <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
               <Warehouse className="text-blue-600" />
               Centros de Distribuição (CD)
             </h3>
             <div className="space-y-4">
               {cds.map(cd => (
                 <div key={cd.id} className="p-4 bg-slate-50 rounded-lg flex items-center justify-between">
                   <div>
                     <p className="font-bold text-slate-800">{cd.name}</p>
                     <p className="text-sm text-slate-500">Código interno: {cd.code}</p>
                   </div>
                   <div className="flex gap-2">
                      <span className="px-3 py-1 bg-blue-100 text-blue-700 rounded text-xs font-bold">PADRÃO</span>
                   </div>
                 </div>
               ))}
               <button 
                onClick={() => alert("Funcionalidade restrita ao suporte TI central.")}
                className="w-full flex items-center justify-center gap-2 px-4 py-3 border-2 border-dashed border-slate-200 text-slate-400 font-bold rounded-lg hover:border-blue-300 hover:text-blue-500 transition-all"
               >
                 <Plus size={20} />
                 Adicionar Novo CD
               </button>
             </div>
          </div>
        );

      default:
        return <div>Em breve...</div>;
    }
  };

  return (
    <Layout 
      user={user} 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      onLogout={handleLogout}
    >
      {renderContent()}
    </Layout>
  );
};

