                onClick={() => {
                  const name = prompt("Nome do Conferente:");
                  const id = prompt("ID do Conferente (Crachá):");
                  if (name && id) {
                    const newChecker: Checker = { id: Math.random().toString(), name, externalId: id, status: 'ATIVO' };
                    setCheckers([...checkers, newChecker]);
                    localStorage.setItem('logi_checkers', JSON.stringify([...checkers, newChecker]));
                  }
                }}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700 shadow-md"
              >
                <UserPlus size={18} />
                Novo Conferente
              </button>
            </div>
            <div className="bg-white rounded-xl border border-slate-200 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-xs font-bold text-slate-500 uppercase">
                  <tr>
                    <th className="px-6 py-4">ID/Crachá</th>
                    <th className="px-6 py-4">Nome Completo</th>
                    <th className="px-6 py-4 text-center">Status</th>
                    <th className="px-6 py-4 text-center">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {checkers.map(c => (
                    <tr key={c.id}>
                      <td className="px-6 py-4 font-mono text-xs">{c.externalId}</td>
                      <td className="px-6 py-4 font-medium">{c.name}</td>
                      <td className="px-6 py-4 text-center">
                        <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${c.status === 'ATIVO' ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                          {c.status}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex justify-center gap-2">
                          <button 
                            onClick={() => {
                              const newList = checkers.map(item => item.id === c.id ? { ...item, status: item.status === 'ATIVO' ? 'INATIVO' : 'ATIVO' } : item) as Checker[];
                              setCheckers(newList);
                              localStorage.setItem('logi_checkers', JSON.stringify(newList));
                            }}
                            className="text-slate-400 hover:text-blue-600 p-1"
                          >
                            Alternar Status
                          </button>
                          <button 
                             onClick={() => {
                              const newList = checkers.filter(item => item.id !== c.id);
                              setCheckers(newList);
                              localStorage.setItem('logi_checkers', JSON.stringify(newList));
                            }}
                            className="text-slate-400 hover:text-red-600 p-1"
                          >
                            <Trash2 size={16} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        );

      case 'branches':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-bold text-slate-800">Gerenciamento de Filiais</h3>
              <button 
                onClick={() => {
                  const name = prompt("Nome da Filial:");
                  const code = prompt("Código da Filial:");
                  if (name && code) {
                    const newBranch: Branch = { id: Math.random().toString(), name, code, city: '-', state: '-', status: 'ATIVO' };
                    setBranches([...branches, newBranch]);
                    localStorage.setItem('logi_branches', JSON.stringify([...branches, newBranch]));
                  }
                }}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700 shadow-md"
              >
                <MapPin size={18} />
                Nova Filial
              </button>
            </div>
            <div className="bg-white rounded-xl border border-slate-200 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-xs font-bold text-slate-500 uppercase">
                  <tr>
                    <th className="px-6 py-4">Código</th>
                    <th className="px-6 py-4">Nome da Filial</th>
                    <th className="px-6 py-4 text-center">Status</th>
                    <th className="px-6 py-4 text-center">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {branches.map(b => (
                    <tr key={b.id}>
                      <td className="px-6 py-4 font-bold text-slate-600">{b.code}</td>
                      <td className="px-6 py-4 font-medium">{b.name}</td>
                      <td className="px-6 py-4 text-center">
                        <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${b.status === 'ATIVO' ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                          {b.status}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex justify-center gap-2">
                          <button 
                            onClick={() => {
                              const newList = branches.filter(item => item.id !== b.id);
                              setBranches(newList);
                              localStorage.setItem('logi_branches', JSON.stringify(newList));
                            }}
                            className="text-slate-400 hover:text-red-600 p-1"
                          >
                            <Trash2 size={16} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        );

      case 'cds':
        return (
          <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm max-w-2xl">
             <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
               <Warehouse className="text-blue-600" />
               Centros de Distribuição (CD)
             </h3>
             <div className="space-y-4">
               {cds.map(cd => (
                 <div key={cd.id} className="p-4 bg-slate-50 rounded-lg flex items-center justify-between">
                   <div>
                     <p className="font-bold text-slate-800">{cd.name}</p>
                     <p className="text-sm text-slate-500">Código interno: {cd.code}</p>
                   </div>
                   <div className="flex gap-2">
                      <span className="px-3 py-1 bg-blue-100 text-blue-700 rounded text-xs font-bold">PADRÃO</span>
                   </div>
                 </div>
               ))}
               <button 
                onClick={() => alert("Funcionalidade restrita ao suporte TI central.")}
                className="w-full flex items-center justify-center gap-2 px-4 py-3 border-2 border-dashed border-slate-200 text-slate-400 font-bold rounded-lg hover:border-blue-300 hover:text-blue-500 transition-all"
               >
                 <Plus size={20} />
                 Adicionar Novo CD
               </button>
             </div>
          </div>
        );

      default:
        return <div>Em breve...</div>;
    }
  };

  return (
    <Layout 
      user={user} 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      onLogout={handleLogout}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

