import { jsPDF } from 'jspdf';
import QRCode from 'qrcode';
import JsBarcode from 'jsbarcode';
import { Manifest } from '../types';

export const generateManifestPDF = async (manifest: Manifest, isPreview: boolean = false): Promise<string | null> => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4',
  });

  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();

  for (let i = 1; i <= manifest.palletsCount; i++) {
    if (i > 1) doc.addPage();

    // Border
    doc.setLineWidth(0.5);
    doc.rect(10, 10, pageWidth - 20, pageHeight - 20);

    // Header - Manifest Number
    doc.setFontSize(10);
    doc.text('MANIFESTO DE CONFERÊNCIA', pageWidth / 2, 20, { align: 'center' });

    doc.setFontSize(48);
    doc.setFont('helvetica', 'bold');
    doc.text(manifest.manifestNumber, pageWidth / 2, 40, { align: 'center' });

    // Barcode
    const canvas = document.createElement('canvas');
    JsBarcode(canvas, manifest.manifestNumber, {
      format: 'CODE128',
      width: 2,
      height: 60,
      displayValue: false
    });
    const barcodeImg = canvas.toDataURL('image/png');
    doc.addImage(barcodeImg, 'PNG', (pageWidth - 100) / 2, 45, 100, 20);

    // Separator
    doc.setLineWidth(0.2);
    doc.line(15, 70, pageWidth - 15, 70);

    // Destination
    doc.setFontSize(14);
    doc.setFont('helvetica', 'normal');
    doc.text('DESTINO:', 20, 85);
    doc.setFontSize(28);
    doc.setFont('helvetica', 'bold');
    doc.text(manifest.branchName, 20, 98);

    // CD Info
    doc.setFontSize(12);
    doc.setFont('helvetica', 'normal');
    doc.text(`ORIGEM (CD): ${manifest.cdName} (${manifest.cdId})`, 20, 110);

    // Details Grid
    doc.setFontSize(12);
    doc.text(`DATA: ${new Date(manifest.conferenceDate).toLocaleDateString('pt-BR')}`, 20, 125);
    doc.text(`CONFERENTE: ${manifest.checkerName}`, 20, 132);

    // Pallet Sequence (LARGE)
    doc.setFontSize(14);
    doc.text('PALETE:', pageWidth - 60, 125);
    doc.setFontSize(42);
    doc.setFont('helvetica', 'bold');
    doc.text(`${i}/${manifest.palletsCount}`, pageWidth - 60, 145);

    // Orders List
    doc.setFontSize(12);
    doc.setFont('helvetica', 'bold');
    doc.text('PEDIDOS NESTE MANIFESTO:', 20, 160);
    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    const splitOrders = doc.splitTextToSize(manifest.orders, pageWidth - 40);
    doc.text(splitOrders, 20, 168);

    // QR Code
    const qrContent = JSON.stringify({
      m: manifest.manifestNumber,
      f: manifest.branchName,
      c: manifest.checkerName,
      p: `${i}/${manifest.palletsCount}`
    });
    const qrDataUrl = await QRCode.toDataURL(qrContent);
    doc.addImage(qrDataUrl, 'PNG', pageWidth - 50, 160, 30, 30);

    // Signature / Label Area
    doc.setLineWidth(0.1);
    doc.setLineDashPattern([2, 2], 0);
    doc.rect(20, pageHeight - 60, pageWidth - 40, 40);
    doc.setFontSize(9);
    doc.text('ESPAÇO RESERVADO PARA ASSINATURA OU ETIQUETA ADICIONAL', pageWidth / 2, pageHeight - 40, { align: 'center' });
    doc.setLineDashPattern([], 0);

    // Footer
    doc.setFontSize(8);
    doc.text(`Gerado em: ${new Date().toLocaleString('pt-BR')} | LogiLabel Pro v1.0`, 20, pageHeight - 15);
  }

  if (isPreview) {
    const blob = doc.output('blob');
    return URL.createObjectURL(blob);
  } else {
    doc.save(`Manifesto_${manifest.manifestNumber}_Etiquetas.pdf`);
    return null;
  }
};

import React, { useState, useEffect } from 'react';
import { 
  FileDown, 
  Eye, 
  Printer, 
  AlertCircle,
  X,
  Loader2,
  CheckCircle2,
  ExternalLink,
  Download
} from 'lucide-react';
import { 
  Checker, 
  Branch, 
  DistributionCenter, 
  Manifest 
} from '../types';
import { generateManifestPDF } from '../services/pdfGenerator';

interface ManifestFormProps {
  checkers: Checker[];
  branches: Branch[];
  cds: DistributionCenter[];
  onSave: (manifest: Manifest) => void;
  currentUser: { name: string; uid: string };
}

const ManifestForm: React.FC<ManifestFormProps> = ({ 
  checkers, 
  branches, 
  cds, 
  onSave,
  currentUser
}) => {
  const [formData, setFormData] = useState({
    manifestNumber: '',
    orders: '',
    conferenceDate: new Date().toISOString().split('T')[0],
    cdId: cds[0]?.id || '',
    branchId: '',
    checkerId: '',
    palletsCount: 1
  });

  const [isPreviewing, setIsPreviewing] = useState(false);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Cleanup Object URL to prevent memory leaks
  useEffect(() => {
    return () => {
      if (previewUrl) {
        URL.revokeObjectURL(previewUrl);
      }
    };
  }, [previewUrl]);

  const activeCheckers = checkers.filter(c => c.status === 'ATIVO');
  const activeBranches = branches.filter(b => b.status === 'ATIVO');

  const validate = () => {
    if (!formData.manifestNumber) return "Número do manifesto é obrigatório";
    if (!formData.orders) return "Lista de pedidos é obrigatória";
    if (!formData.branchId) return "Selecione uma filial de destino";
    if (!formData.checkerId) return "Selecione um conferente";
    if (formData.palletsCount < 1) return "Quantidade de paletes deve ser pelo menos 1";
    return null;
  };

  const constructManifest = (): Manifest => {
    const cd = cds.find(c => c.id === formData.cdId);
    const branch = branches.find(b => b.id === formData.branchId);
    const checker = checkers.find(c => c.id === formData.checkerId);

    return {
      id: Math.random().toString(36).substr(2, 9),
      ...formData,
      createdAt: new Date().toISOString(),
      createdBy: currentUser.name,
      cdName: cd?.name || '',
      branchName: branch?.name || '',
      checkerName: checker?.name || ''
    };
  };

  const handlePreview = async () => {
    const err = validate();
    if (err) {
      setError(err);
      return;
    }
    setError(null);
    setIsGenerating(true);
    try {
      if (previewUrl) URL.revokeObjectURL(previewUrl);
      const manifest = constructManifest();
      const url = await generateManifestPDF(manifest, true);
      setPreviewUrl(url);
      setIsPreviewing(true);
    } catch (e) {
      setError("Erro ao gerar pré-visualização.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = async () => {
    const err = validate();
    if (err) {
      setError(err);
      return;
    }
    setError(null);
    setIsGenerating(true);
    try {
      const manifest = constructManifest();
      await generateManifestPDF(manifest, false);
      onSave(manifest);
      setFormData({
        ...formData,
        manifestNumber: '',
        orders: '',
        palletsCount: 1
      });
    } catch (e) {
      setError("Erro ao salvar manifesto.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="bg-white p-4 lg:p-8 rounded-xl border border-slate-200 shadow-sm space-y-6">
        <div className="flex items-center gap-3 border-b border-slate-100 pb-4">
          <CheckCircle2 className="text-blue-600 shrink-0" />
          <h2 className="text-lg lg:text-xl font-bold text-slate-800">Nova Conferência</h2>
        </div>

        {error && (
          <div className="bg-red-50 border-l-4 border-red-500 p-4 flex items-center gap-3 text-red-700 text-sm">
            <AlertCircle size={18} className="shrink-0" />
            <p>{error}</p>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Número do Manifesto *</label>
              <input
                type="text"
                placeholder="Ex: 559082"
                className="w-full px-4 py-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all text-base"
                value={formData.manifestNumber}
                onChange={e => setFormData({ ...formData, manifestNumber: e.target.value.toUpperCase() })}
              />
            </div>

            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Centro de Distribuição *</label>
              <select
                className="w-full px-4 py-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all bg-white text-base"
                value={formData.cdId}
                onChange={e => setFormData({ ...formData, cdId: e.target.value })}
              >
                {cds.map(cd => <option key={cd.id} value={cd.id}>{cd.name} ({cd.code})</option>)}
              </select>
            </div>

            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Filial de Destino *</label>
              <select
                className="w-full px-4 py-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all bg-white text-base"
                value={formData.branchId}
                onChange={e => setFormData({ ...formData, branchId: e.target.value })}
              >
                <option value="">Selecione a Filial...</option>
                {activeBranches.map(b => <option key={b.id} value={b.id}>{b.name} ({b.code})</option>)}
              </select>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-1">Data *</label>
                <input
                  type="date"
                  className="w-full px-4 py-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-base"
                  value={formData.conferenceDate}
                  onChange={e => setFormData({ ...formData, conferenceDate: e.target.value })}
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-1">Paletes *</label>
                <input
                  type="number"
                  min="1"
                  max="50"
                  className="w-full px-4 py-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-base"
                  value={formData.palletsCount}
                  onChange={e => setFormData({ ...formData, palletsCount: parseInt(e.target.value) || 1 })}
                />
              </div>
            </div>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Conferente Responsável *</label>
              <select
                className="w-full px-4 py-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all bg-white text-base"
                value={formData.checkerId}
                onChange={e => setFormData({ ...formData, checkerId: e.target.value })}
              >
                <option value="">Selecione o Conferente...</option>
                {activeCheckers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
            </div>

            <div>
              <label className="block text-sm font-bold text-slate-700 mb-1">Lista de Pedidos *</label>
              <textarea
                rows={5}
                placeholder="Insira os números dos pedidos..."
                className="w-full px-4 py-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all resize-none text-base"
                value={formData.orders}
                onChange={e => setFormData({ ...formData, orders: e.target.value })}
              />
            </div>
          </div>
        </div>

        <div className="flex flex-col sm:flex-row gap-3 pt-6 border-t border-slate-100">
          <button
            onClick={handlePreview}
            disabled={isGenerating}
            className="flex-1 flex items-center justify-center gap-2 px-6 py-4 bg-slate-100 text-slate-700 font-bold rounded-xl hover:bg-slate-200 transition-colors disabled:opacity-50"
          >
            {isGenerating ? <Loader2 className="animate-spin" /> : <Eye size={20} />}
