          </button>
          <button
            onClick={handleDownload}
            disabled={isGenerating}
            className="flex-1 flex items-center justify-center gap-2 px-6 py-4 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-700 shadow-lg shadow-blue-200 transition-all disabled:opacity-50"
          >
            {isGenerating ? <Loader2 className="animate-spin" /> : <FileDown size={20} />}
            Gerar Etiquetas
          </button>
        </div>
      </div>

      {/* Preview Modal com tratamento de erro e responsividade */}
      {isPreviewing && previewUrl && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-0 lg:p-4 bg-black/80 backdrop-blur-sm">
