  const [checkers, setCheckers] = useState<Checker[]>(INITIAL_CHECKERS);
  const [branches, setBranches] = useState<Branch[]>(INITIAL_BRANCHES);
  const [cds, setCds] = useState<DistributionCenter[]>(INITIAL_CDS);

  // Search/Filter State
  const [searchTerm, setSearchTerm] = useState('');

  // Modals / Add Forms State
  const [showAddChecker, setShowAddChecker] = useState(false);
  const [showAddBranch, setShowAddBranch] = useState(false);
  const [showAddCD, setShowAddCD] = useState(false);

  // Form states for new entities
  const [newChecker, setNewChecker] = useState({ name: '', externalId: '' });
  const [newBranch, setNewBranch] = useState({ name: '', code: '', city: '', state: '' });
  const [newCD, setNewCD] = useState({ name: '', code: '' });

  // Local Storage persistence
  useEffect(() => {
    const savedManifests = localStorage.getItem('logi_manifests');
    if (savedManifests) setManifests(JSON.parse(savedManifests));

    const savedCheckers = localStorage.getItem('logi_checkers');
    if (savedCheckers) setCheckers(JSON.parse(savedCheckers));

    const savedBranches = localStorage.getItem('logi_branches');
    if (savedBranches) setBranches(JSON.parse(savedBranches));

    const savedCDs = localStorage.getItem('logi_cds');
    if (savedCDs) setCds(JSON.parse(savedCDs));

    const savedUser = localStorage.getItem('logi_user');
    if (savedUser) setUser(JSON.parse(savedUser));
  }, []);

  // Sync state to local storage when changed
  useEffect(() => {
    localStorage.setItem('logi_manifests', JSON.stringify(manifests));
  }, [manifests]);

  useEffect(() => {
    localStorage.setItem('logi_checkers', JSON.stringify(checkers));
  }, [checkers]);

  useEffect(() => {
    localStorage.setItem('logi_branches', JSON.stringify(branches));
  }, [branches]);

  useEffect(() => {
    localStorage.setItem('logi_cds', JSON.stringify(cds));
  }, [cds]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError(null);

    const emailInput = loginForm.email.toLowerCase();
    const passwordInput = loginForm.password;

    if ((emailInput === 'diego.silva' || emailInput === 'diego.silva@logi.com') && passwordInput === '05171888302') {
      const u: UserProfile = { uid: 'u_diego', email: 'diego.silva@logi.com', name: 'Diego Silva', role: 'ADMIN' };
      setUser(u);
      localStorage.setItem('logi_user', JSON.stringify(u));
    } else if (emailInput === 'admin@logi.com' && passwordInput === 'admin123') {
      const u: UserProfile = { uid: 'u1', email: 'admin@logi.com', name: 'Administrador CD', role: 'ADMIN' };
      setUser(u);
      localStorage.setItem('logi_user', JSON.stringify(u));
    } else if (emailInput === 'conferente@logi.com' && passwordInput === 'conf123') {
      const u: UserProfile = { uid: 'u2', email: 'conferente@logi.com', name: 'João Conferente', role: 'CONFERENTE' };
      setUser(u);
      localStorage.setItem('logi_user', JSON.stringify(u));
    } else {
      setLoginError('Credenciais inválidas. Verifique seu usuário e senha.');
    }
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('logi_user');
  };

  // Add Handlers
  const handleAddChecker = (e: React.FormEvent) => {
    e.preventDefault();
    if (newChecker.name && newChecker.externalId) {
      const checker: Checker = {
        id: Math.random().toString(36).substr(2, 9),
        name: newChecker.name,
        externalId: newChecker.externalId,
        status: 'ATIVO'
      };
      setCheckers([...checkers, checker]);
      setNewChecker({ name: '', externalId: '' });
      setShowAddChecker(false);
    }
  };

  const handleAddBranch = (e: React.FormEvent) => {
    e.preventDefault();
    if (newBranch.name && newBranch.code) {
      const branch: Branch = {
        id: Math.random().toString(36).substr(2, 9),
        ...newBranch,
        status: 'ATIVO'
      };
      setBranches([...branches, branch]);
      setNewBranch({ name: '', code: '', city: '', state: '' });
      setShowAddBranch(false);
    }
  };

  const handleAddCD = (e: React.FormEvent) => {
    e.preventDefault();
    if (newCD.name && newCD.code) {
      const cd: DistributionCenter = {
        id: Math.random().toString(36).substr(2, 9),
        ...newCD
      };
      setCds([...cds, cd]);
      setNewCD({ name: '', code: '' });
      setShowAddCD(false);
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-100 p-4">
        <div className="max-w-md w-full bg-white rounded-2xl shadow-xl overflow-hidden">
          <div className="bg-slate-900 p-8 text-center">
            <div className="inline-flex items-center justify-center p-3 bg-blue-600 rounded-xl mb-4 text-white shadow-lg shadow-blue-900/40">
              <Warehouse size={32} />
            </div>
            <h1 className="text-2xl font-bold text-white">LogiLabel Pro</h1>
            <p className="text-slate-400 text-sm mt-1">Gestão de Etiquetas para CD</p>
          </div>
          <div className="p-8">
            <form onSubmit={handleLogin} className="space-y-6">
              {loginError && (
                <div className="p-3 bg-red-50 text-red-600 text-xs rounded-lg border border-red-100 flex gap-2">
                  <Lock size={14} className="flex-shrink-0" />
                  {loginError}
                </div>
              )}
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Usuário / Email</label>
                <input
                  type="text"
                  className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  placeholder="Seu usuário ou email"
                  value={loginForm.email}
                  onChange={e => setLoginForm({...loginForm, email: e.target.value})}
                  required
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Senha</label>
                <input
                  type="password"
                  className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  placeholder="••••••••"
                  value={loginForm.password}
                  onChange={e => setLoginForm({...loginForm, password: e.target.value})}
                  required
                />
              </div>
              <button 
                type="submit"
                className="w-full py-4 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-700 shadow-lg shadow-blue-200 active:scale-95 transition-all"
              >
                Acessar Sistema
              </button>
            </form>
            <div className="mt-8 pt-6 border-t border-slate-100 text-center">
              <p className="text-[10px] text-slate-400 font-medium">© 2024 LogiLabel Pro Systems. Versão 1.0.4</p>
            </div>
          </div>
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard manifests={manifests} />;

      case 'generate':
        return (
          <ManifestForm 
            checkers={checkers}
            branches={branches}
            cds={cds}
            onSave={(m) => setManifests([m, ...manifests])}
            currentUser={user}
          />
        );

      case 'history':
        const filteredManifests = manifests.filter(m => 
          m.manifestNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
          m.branchName.toLowerCase().includes(searchTerm.toLowerCase()) ||
          m.checkerName.toLowerCase().includes(searchTerm.toLowerCase())
        );

        return (
          <div className="space-y-6">
            <div className="flex flex-col md:flex-row gap-4 items-center justify-between bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <div className="relative w-full md:w-96">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                  type="text" 
                  placeholder="Buscar por manifesto, filial ou conferente..."
                  className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                />
              </div>
              <div className="flex gap-2 w-full md:w-auto">
                <button 
                  onClick={() => setSearchTerm('')}
                  className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-slate-100 text-slate-600 rounded-lg hover:bg-slate-200"
                >
                  <RefreshCcw size={18} />
                  Limpar
                </button>
              </div>
            </div>

            <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left min-w-[800px]">
                  <thead className="bg-slate-50 text-slate-500 text-xs uppercase font-bold tracking-wider">
                    <tr>
                      <th className="px-6 py-4">Manifesto</th>
                      <th className="px-6 py-4">Data Conf.</th>
                      <th className="px-6 py-4">CD Origem</th>
                      <th className="px-6 py-4">Destino</th>
                      <th className="px-6 py-4">Conferente</th>
                      <th className="px-6 py-4">Paletes</th>
                      <th className="px-6 py-4 text-center">Ações</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100 text-sm">
                    {filteredManifests.map((m) => (
                      <tr key={m.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-6 py-4 font-bold text-slate-800">{m.manifestNumber}</td>
                        <td className="px-6 py-4 text-slate-500">{new Date(m.conferenceDate).toLocaleDateString('pt-BR')}</td>
                        <td className="px-6 py-4 text-slate-500">{m.cdName}</td>
                        <td className="px-6 py-4 font-medium text-slate-700">{m.branchName}</td>
                        <td className="px-6 py-4 text-slate-500">{m.checkerName}</td>
                        <td className="px-6 py-4">
                          <span className="px-2 py-1 bg-blue-50 text-blue-600 rounded text-xs font-bold">{m.palletsCount} un.</span>
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex justify-center gap-2">
                            <button 
                              title="Reimprimir Etiquetas"
                              onClick={() => generateManifestPDF(m, false)}
                              className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                            >
                              <Printer size={18} />
                            </button>
                            {user.role === 'ADMIN' && (
                              <button 
                                title="Excluir Registro"
                                onClick={() => {
                                  if(confirm("Deseja realmente excluir este manifesto do histórico?")) {
                                    setManifests(manifests.filter(x => x.id !== m.id));
                                  }
                                }}
                                className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                              >
                                <Trash2 size={18} />
                              </button>
                            )}
                          </div>
                        </td>
                      </tr>
                    ))}
                    {filteredManifests.length === 0 && (
                      <tr>
                        <td colSpan={7} className="px-6 py-12 text-center text-slate-400">Nenhum manifesto encontrado.</td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        );

      case 'checkers':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-bold text-slate-800">Gerenciamento de Conferentes</h3>
              <button 
                onClick={() => setShowAddChecker(true)}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700 shadow-md transition-all active:scale-95"
              >
                <UserPlus size={18} />
                Novo Conferente
              </button>
            </div>

            {showAddChecker && (
              <div className="bg-blue-50 p-6 rounded-xl border border-blue-200 shadow-inner">
                <form onSubmit={handleAddChecker} className="flex flex-col md:flex-row gap-4">
                  <div className="flex-1">
                    <label className="block text-xs font-bold text-blue-700 uppercase mb-1">Nome Completo</label>
                    <input 
                      type="text" 
                      required
                      className="w-full px-4 py-2 border border-blue-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                      value={newChecker.name}
                      onChange={e => setNewChecker({...newChecker, name: e.target.value})}
                    />
                  </div>
                  <div className="md:w-48">
                    <label className="block text-xs font-bold text-blue-700 uppercase mb-1">ID/Crachá</label>
                    <input 
                      type="text" 
                      required
                      className="w-full px-4 py-2 border border-blue-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                      value={newChecker.externalId}
                      onChange={e => setNewChecker({...newChecker, externalId: e.target.value})}
                    />
                  </div>
                  <div className="flex items-end gap-2">
                    <button type="submit" className="px-6 py-2 bg-blue-600 text-white font-bold rounded-lg hover:bg-blue-700 flex items-center gap-2">
                      <Check size={18} /> Salvar
                    </button>
                    <button type="button" onClick={() => setShowAddChecker(false)} className="px-4 py-2 bg-white text-slate-600 border border-slate-200 font-bold rounded-lg hover:bg-slate-50">
                      Cancelar
                    </button>
                  </div>
                </form>
              </div>
            )}

            <div className="bg-white rounded-xl border border-slate-200 overflow-hidden shadow-sm">
              <div className="overflow-x-auto">
                <table className="w-full text-left min-w-[600px]">
                  <thead className="bg-slate-50 text-xs font-bold text-slate-500 uppercase">
                    <tr>
                      <th className="px-6 py-4">ID/Crachá</th>
                      <th className="px-6 py-4">Nome Completo</th>
                      <th className="px-6 py-4 text-center">Status</th>
                      <th className="px-6 py-4 text-center">Ações</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {checkers.map(c => (
                      <tr key={c.id}>
                        <td className="px-6 py-4 font-mono text-xs">{c.externalId}</td>
                        <td className="px-6 py-4 font-medium">{c.name}</td>
                        <td className="px-6 py-4 text-center">
                          <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${c.status === 'ATIVO' ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                            {c.status}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex justify-center gap-4">
                            <button 
                              onClick={() => {
                                const newList = checkers.map(item => item.id === c.id ? { ...item, status: item.status === 'ATIVO' ? 'INATIVO' : 'ATIVO' } : item) as Checker[];
                                setCheckers(newList);
                              }}
                              className="text-xs font-bold text-blue-600 hover:underline"
                            >
                              Alternar Status
                            </button>
                            <button 
                               onClick={() => {
                                if(confirm("Deseja excluir este conferente?")) {
                                  setCheckers(checkers.filter(item => item.id !== c.id));
                                }
                              }}
                              className="text-slate-400 hover:text-red-600 transition-colors"
                            >
                              <Trash2 size={16} />
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        );

      case 'branches':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-bold text-slate-800">Gerenciamento de Filiais</h3>
              <button 
                onClick={() => setShowAddBranch(true)}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700 shadow-md transition-all active:scale-95"
              >
                <MapPin size={18} />
                Nova Filial
              </button>
            </div>

            {showAddBranch && (
              <div className="bg-emerald-50 p-6 rounded-xl border border-emerald-200 shadow-inner">
                <form onSubmit={handleAddBranch} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                  <div>
                    <label className="block text-xs font-bold text-emerald-700 uppercase mb-1">Nome da Filial</label>
                    <input 
                      type="text" 
                      required
                      className="w-full px-4 py-2 border border-emerald-200 rounded-lg outline-none focus:ring-2 focus:ring-emerald-500"
                      value={newBranch.name}
                      onChange={e => setNewBranch({...newBranch, name: e.target.value})}
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-emerald-700 uppercase mb-1">Código</label>
                    <input 
                      type="text" 
                      required
                      className="w-full px-4 py-2 border border-emerald-200 rounded-lg outline-none focus:ring-2 focus:ring-emerald-500"
                      value={newBranch.code}
                      onChange={e => setNewBranch({...newBranch, code: e.target.value})}
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-emerald-700 uppercase mb-1">Cidade / UF</label>
                    <input 
                      type="text" 
                      placeholder="Ex: São Paulo - SP"
                      className="w-full px-4 py-2 border border-emerald-200 rounded-lg outline-none focus:ring-2 focus:ring-emerald-500"
                      value={newBranch.city}
                      onChange={e => setNewBranch({...newBranch, city: e.target.value})}
                    />
                  </div>
                  <div className="flex items-end gap-2">
                    <button type="submit" className="flex-1 py-2 bg-emerald-600 text-white font-bold rounded-lg hover:bg-emerald-700 flex items-center justify-center gap-2">
                      <Check size={18} /> Salvar
                    </button>
                    <button type="button" onClick={() => setShowAddBranch(false)} className="px-4 py-2 bg-white text-slate-600 border border-slate-200 font-bold rounded-lg hover:bg-slate-50">
                      <X size={18} />
                    </button>
                  </div>
                </form>
              </div>
            )}

            <div className="bg-white rounded-xl border border-slate-200 overflow-hidden shadow-sm">
              <div className="overflow-x-auto">
                <table className="w-full text-left min-w-[600px]">
                  <thead className="bg-slate-50 text-xs font-bold text-slate-500 uppercase">
                    <tr>
                      <th className="px-6 py-4">Código</th>
                      <th className="px-6 py-4">Nome da Filial</th>
                      <th className="px-6 py-4">Localização</th>
                      <th className="px-6 py-4 text-center">Ações</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {branches.map(b => (
                      <tr key={b.id}>
                        <td className="px-6 py-4 font-bold text-slate-600">{b.code}</td>
                        <td className="px-6 py-4 font-medium">{b.name}</td>
                        <td className="px-6 py-4 text-slate-500">{b.city || 'Não inf.'}</td>
                        <td className="px-6 py-4">
                          <div className="flex justify-center gap-2">
                            <button 
                              onClick={() => {
                                if(confirm("Excluir filial?")) {
                                  setBranches(branches.filter(item => item.id !== b.id));
                                }
                              }}
                              className="text-slate-400 hover:text-red-600 p-1 transition-colors"
                            >
                              <Trash2 size={16} />
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        );

      case 'cds':
        return (
          <div className="max-w-3xl space-y-6">
            <div className="flex justify-between items-center">
               <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                 <Warehouse className="text-blue-600" />
                 Centros de Distribuição (CD)
               </h3>
               <button 
                onClick={() => setShowAddCD(true)}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700 shadow-md transition-all active:scale-95"
               >
                 <Plus size={18} />
                 Novo CD
               </button>
            </div>

            {showAddCD && (
              <div className="bg-slate-100 p-6 rounded-xl border border-slate-200 shadow-inner">
                <form onSubmit={handleAddCD} className="flex flex-col md:flex-row gap-4">
                  <div className="flex-1">
                    <label className="block text-xs font-bold text-slate-700 uppercase mb-1">Nome do CD</label>
                    <input 
                      type="text" 
                      required
                      className="w-full px-4 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                      value={newCD.name}
                      onChange={e => setNewCD({...newCD, name: e.target.value})}
                    />
                  </div>
                  <div className="md:w-48">
                    <label className="block text-xs font-bold text-slate-700 uppercase mb-1">Código</label>
                    <input 
                      type="text" 
                      required
                      className="w-full px-4 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                      value={newCD.code}
                      onChange={e => setNewCD({...newCD, code: e.target.value})}
                    />
                  </div>
                  <div className="flex items-end gap-2">
                    <button type="submit" className="px-6 py-2 bg-blue-600 text-white font-bold rounded-lg hover:bg-blue-700 flex items-center gap-2">
                      <Check size={18} /> Salvar
                    </button>
                    <button type="button" onClick={() => setShowAddCD(false)} className="px-4 py-2 bg-white text-slate-600 border border-slate-200 font-bold rounded-lg hover:bg-slate-50">
                      <X size={18} />
                    </button>
                  </div>
                </form>
              </div>
            )}

            <div className="space-y-4">
               {cds.map(cd => (
                 <div key={cd.id} className="p-4 bg-white rounded-xl border border-slate-200 shadow-sm flex items-center justify-between group">
                   <div className="flex items-center gap-4">
                     <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
                       <Warehouse size={24} />
                     </div>
                     <div>
                       <p className="font-bold text-slate-800">{cd.name}</p>
                       <p className="text-sm text-slate-500 font-mono">Código: {cd.code}</p>
                     </div>
                   </div>
                   <div className="flex gap-2">
                      <button 
                        onClick={() => {
                          if(confirm(`Excluir ${cd.name}?`)) {
                            setCds(cds.filter(x => x.id !== cd.id));
                          }
                        }}
                        className="p-2 text-slate-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"
                      >
                        <Trash2 size={18} />
                      </button>
                      <span className="px-3 py-1 bg-blue-100 text-blue-700 rounded text-[10px] font-bold h-fit self-center">OPERANTE</span>
                   </div>
                 </div>
               ))}
            </div>
          </div>
        );

      default:
        return <div>Em breve...</div>;
    }
  };

  return (
    <Layout 
      user={user} 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      onLogout={handleLogout}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ManifestForm from './components/ManifestForm';
import { 
  UserProfile, 
  Manifest, 
  Checker, 
  Branch, 
  DistributionCenter 
} from './types';
import { 
  INITIAL_CHECKERS, 
  INITIAL_BRANCHES, 
  INITIAL_CDS 
} from './services/mockData';
import { 
  Search, 
  Filter, 
  RefreshCcw, 
  Printer, 
  Plus, 
  Trash2, 
  UserPlus, 
  MapPin, 
  Warehouse,
  Lock,
  X,
  Check
} from 'lucide-react';
import { generateManifestPDF } from './services/pdfGenerator';

const App: React.FC = () => {
  // --- Lazy State Initialization (Prevents race conditions with LocalStorage) ---

  const [user, setUser] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('logi_user');
    return saved ? JSON.parse(saved) : null;
  });

  const [manifests, setManifests] = useState<Manifest[]>(() => {
    const saved = localStorage.getItem('logi_manifests');
    return saved ? JSON.parse(saved) : [];
  });

  const [checkers, setCheckers] = useState<Checker[]>(() => {
    const saved = localStorage.getItem('logi_checkers');
    return saved ? JSON.parse(saved) : INITIAL_CHECKERS;
  });

  const [branches, setBranches] = useState<Branch[]>(() => {
    const saved = localStorage.getItem('logi_branches');
    return saved ? JSON.parse(saved) : INITIAL_BRANCHES;
  });

  const [cds, setCds] = useState<DistributionCenter[]>(() => {
    const saved = localStorage.getItem('logi_cds');
    return saved ? JSON.parse(saved) : INITIAL_CDS;
  });

  // UI States
  const [loginForm, setLoginForm] = useState({ email: '', password: '' });
  const [loginError, setLoginError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [searchTerm, setSearchTerm] = useState('');

  // Modals / Add Forms State
  const [showAddChecker, setShowAddChecker] = useState(false);
  const [showAddBranch, setShowAddBranch] = useState(false);
  const [showAddCD, setShowAddCD] = useState(false);

  // Form states for new entities
  const [newChecker, setNewChecker] = useState({ name: '', externalId: '' });
  const [newBranch, setNewBranch] = useState({ name: '', code: '', city: '', state: '' });
  const [newCD, setNewCD] = useState({ name: '', code: '' });

  // --- Persistence Effects ---
  useEffect(() => {
    localStorage.setItem('logi_manifests', JSON.stringify(manifests));
  }, [manifests]);

  useEffect(() => {
    localStorage.setItem('logi_checkers', JSON.stringify(checkers));
  }, [checkers]);

  useEffect(() => {
    localStorage.setItem('logi_branches', JSON.stringify(branches));
  }, [branches]);

  useEffect(() => {
    localStorage.setItem('logi_cds', JSON.stringify(cds));
  }, [cds]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError(null);

    const emailInput = loginForm.email.toLowerCase();
    const passwordInput = loginForm.password;

    if ((emailInput === 'diego.silva' || emailInput === 'diego.silva@logi.com') && passwordInput === '05171888302') {
      const u: UserProfile = { uid: 'u_diego', email: 'diego.silva@logi.com', name: 'Diego Silva', role: 'ADMIN' };
      setUser(u);
      localStorage.setItem('logi_user', JSON.stringify(u));
    } else if (emailInput === 'admin@logi.com' && passwordInput === 'admin123') {
      const u: UserProfile = { uid: 'u1', email: 'admin@logi.com', name: 'Administrador CD', role: 'ADMIN' };
      setUser(u);
      localStorage.setItem('logi_user', JSON.stringify(u));
    } else if (emailInput === 'conferente@logi.com' && passwordInput === 'conf123') {
      const u: UserProfile = { uid: 'u2', email: 'conferente@logi.com', name: 'João Conferente', role: 'CONFERENTE' };
      setUser(u);
      localStorage.setItem('logi_user', JSON.stringify(u));
    } else {
      setLoginError('Credenciais inválidas. Verifique seu usuário e senha.');
    }
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('logi_user');
  };

  // Add Handlers
  const handleAddChecker = (e: React.FormEvent) => {
    e.preventDefault();
    if (newChecker.name && newChecker.externalId) {
      const checker: Checker = {
        id: `c_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
        name: newChecker.name,
        externalId: newChecker.externalId,
        status: 'ATIVO'
      };
      setCheckers(prev => [...prev, checker]);
      setNewChecker({ name: '', externalId: '' });
      setShowAddChecker(false);
    }
  };

  const handleAddBranch = (e: React.FormEvent) => {
    e.preventDefault();
    if (newBranch.name && newBranch.code) {
      const branch: Branch = {
        id: `b_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
        ...newBranch,
        status: 'ATIVO'
      };
      setBranches(prev => [...prev, branch]);
      setNewBranch({ name: '', code: '', city: '', state: '' });
      setShowAddBranch(false);
    }
  };

  const handleAddCD = (e: React.FormEvent) => {
    e.preventDefault();
    if (newCD.name && newCD.code) {
      const cd: DistributionCenter = {
        id: `cd_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
        ...newCD
      };
      setCds(prev => [...prev, cd]);
      setNewCD({ name: '', code: '' });
      setShowAddCD(false);
    }
  };

  // Delete Handlers
  const deleteChecker = (id: string) => {
    if (confirm("Deseja realmente excluir este conferente do sistema?")) {
      setCheckers(prev => prev.filter(c => c.id !== id));
    }
  };

  const deleteBranch = (id: string) => {
    if (confirm("Deseja excluir esta filial?")) {
      setBranches(prev => prev.filter(b => b.id !== id));
    }
  };

  const deleteCD = (id: string, name: string) => {
    if (confirm(`Tem certeza que deseja excluir o Centro de Distribuição: ${name}?`)) {
      setCds(prev => prev.filter(cd => cd.id !== id));
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-100 p-4">
        <div className="max-w-md w-full bg-white rounded-2xl shadow-xl overflow-hidden">
          <div className="bg-slate-900 p-8 text-center">
            <div className="inline-flex items-center justify-center p-3 bg-blue-600 rounded-xl mb-4 text-white shadow-lg shadow-blue-900/40">
              <Warehouse size={32} />
            </div>
            <h1 className="text-2xl font-bold text-white">LogiLabel Pro</h1>
            <p className="text-slate-400 text-sm mt-1">Gestão de Etiquetas para CD</p>
          </div>
          <div className="p-8">
            <form onSubmit={handleLogin} className="space-y-6">
              {loginError && (
                <div className="p-3 bg-red-50 text-red-600 text-xs rounded-lg border border-red-100 flex gap-2">
                  <Lock size={14} className="flex-shrink-0" />
                  {loginError}
                </div>
              )}
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Usuário / Email</label>
                <input
                  type="text"
                  className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  placeholder="Seu usuário ou email"
                  value={loginForm.email}
                  onChange={e => setLoginForm({...loginForm, email: e.target.value})}
                  required
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Senha</label>
                <input
                  type="password"
                  className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  placeholder="••••••••"
                  value={loginForm.password}
                  onChange={e => setLoginForm({...loginForm, password: e.target.value})}
                  required
                />
              </div>
              <button 
                type="submit"
                className="w-full py-4 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-700 shadow-lg shadow-blue-200 active:scale-95 transition-all"
              >
                Acessar Sistema
              </button>
            </form>
            <div className="mt-8 pt-6 border-t border-slate-100 text-center">
              <p className="text-[10px] text-slate-400 font-medium">© 2024 LogiLabel Pro Systems. Versão 1.0.5</p>
            </div>
          </div>
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard manifests={manifests} />;

      case 'generate':
        return (
          <ManifestForm 
            checkers={checkers}
            branches={branches}
            cds={cds}
            onSave={(m) => setManifests(prev => [m, ...prev])}
            currentUser={user}
          />
        );

      case 'history':
        const filteredManifests = manifests.filter(m => 
          m.manifestNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
          m.branchName.toLowerCase().includes(searchTerm.toLowerCase()) ||
          m.checkerName.toLowerCase().includes(searchTerm.toLowerCase())
        );

        return (
          <div className="space-y-6">
            <div className="flex flex-col md:flex-row gap-4 items-center justify-between bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <div className="relative w-full md:w-96">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                  type="text" 
                  placeholder="Buscar por manifesto, filial ou conferente..."
                  className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                />
              </div>
              <div className="flex gap-2 w-full md:w-auto">
                <button 
                  onClick={() => setSearchTerm('')}
                  className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-slate-100 text-slate-600 rounded-lg hover:bg-slate-200"
                >
                  <RefreshCcw size={18} />
                  Limpar
                </button>
              </div>
            </div>

            <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left min-w-[800px]">
                  <thead className="bg-slate-50 text-slate-500 text-xs uppercase font-bold tracking-wider">
                    <tr>
                      <th className="px-6 py-4">Manifesto</th>
                      <th className="px-6 py-4">Data Conf.</th>
                      <th className="px-6 py-4">CD Origem</th>
                      <th className="px-6 py-4">Destino</th>
                      <th className="px-6 py-4">Conferente</th>
                      <th className="px-6 py-4">Paletes</th>
                      <th className="px-6 py-4 text-center">Ações</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100 text-sm">
                    {filteredManifests.map((m) => (
                      <tr key={m.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-6 py-4 font-bold text-slate-800">{m.manifestNumber}</td>
                        <td className="px-6 py-4 text-slate-500">{new Date(m.conferenceDate).toLocaleDateString('pt-BR')}</td>
                        <td className="px-6 py-4 text-slate-500">{m.cdName}</td>
                        <td className="px-6 py-4 font-medium text-slate-700">{m.branchName}</td>
                        <td className="px-6 py-4 text-slate-500">{m.checkerName}</td>
                        <td className="px-6 py-4">
                          <span className="px-2 py-1 bg-blue-50 text-blue-600 rounded text-xs font-bold">{m.palletsCount} un.</span>
                        </td>
                        <td className="px-6 py-4 text-center">
                          <div className="flex justify-center gap-2">
                            <button 
                              title="Reimprimir Etiquetas"
                              onClick={() => generateManifestPDF(m, false)}
                              className="p-2 text-blue-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                            >
                              <Printer size={18} />
                            </button>
                            {user.role === 'ADMIN' && (
                              <button 
                                title="Excluir Registro"
                                onClick={() => {
                                  if(confirm("Deseja realmente excluir este manifesto do histórico?")) {
                                    setManifests(prev => prev.filter(x => x.id !== m.id));
                                  }
                                }}
                                className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                              >
                                <Trash2 size={18} />
                              </button>
                            )}
                          </div>
                        </td>
                      </tr>
                    ))}
                    {filteredManifests.length === 0 && (
                      <tr>
                        <td colSpan={7} className="px-6 py-12 text-center text-slate-400">Nenhum manifesto encontrado.</td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        );

      case 'checkers':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-bold text-slate-800">Gerenciamento de Conferentes</h3>
              <button 
                onClick={() => setShowAddChecker(true)}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700 shadow-md transition-all active:scale-95"
              >
                <UserPlus size={18} />
                Novo Conferente
              </button>
            </div>

            {showAddChecker && (
              <div className="bg-blue-50 p-6 rounded-xl border border-blue-200 shadow-inner">
                <form onSubmit={handleAddChecker} className="flex flex-col md:flex-row gap-4">
                  <div className="flex-1">
                    <label className="block text-xs font-bold text-blue-700 uppercase mb-1">Nome Completo</label>
                    <input 
                      type="text" 
                      required
                      className="w-full px-4 py-2 border border-blue-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                      value={newChecker.name}
                      onChange={e => setNewChecker({...newChecker, name: e.target.value})}
                    />
                  </div>
                  <div className="md:w-48">
                    <label className="block text-xs font-bold text-blue-700 uppercase mb-1">ID/Crachá</label>
                    <input 
                      type="text" 
                      required
                      className="w-full px-4 py-2 border border-blue-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                      value={newChecker.externalId}
                      onChange={e => setNewChecker({...newChecker, externalId: e.target.value})}
                    />
                  </div>
                  <div className="flex items-end gap-2">
                    <button type="submit" className="px-6 py-2 bg-blue-600 text-white font-bold rounded-lg hover:bg-blue-700 flex items-center gap-2">
                      <Check size={18} /> Salvar
                    </button>
                    <button type="button" onClick={() => setShowAddChecker(false)} className="px-4 py-2 bg-white text-slate-600 border border-slate-200 font-bold rounded-lg hover:bg-slate-50">
                      Cancelar
                    </button>
                  </div>
                </form>
              </div>
            )}

            <div className="bg-white rounded-xl border border-slate-200 overflow-hidden shadow-sm">
              <div className="overflow-x-auto">
                <table className="w-full text-left min-w-[600px]">
                  <thead className="bg-slate-50 text-xs font-bold text-slate-500 uppercase">
                    <tr>
                      <th className="px-6 py-4">ID/Crachá</th>
                      <th className="px-6 py-4">Nome Completo</th>
                      <th className="px-6 py-4 text-center">Status</th>
                      <th className="px-6 py-4 text-center">Ações</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {checkers.map(c => (
                      <tr key={c.id}>
                        <td className="px-6 py-4 font-mono text-xs">{c.externalId}</td>
                        <td className="px-6 py-4 font-medium">{c.name}</td>
                        <td className="px-6 py-4 text-center">
                          <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${c.status === 'ATIVO' ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                            {c.status}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex justify-center gap-4">
                            <button 
                              onClick={() => {
                                const newList = checkers.map(item => item.id === c.id ? { ...item, status: item.status === 'ATIVO' ? 'INATIVO' : 'ATIVO' } : item) as Checker[];
                                setCheckers(newList);
                              }}
                              className="text-xs font-bold text-blue-600 hover:underline"
                            >
                              Alternar Status
                            </button>
                            <button 
                               onClick={() => deleteChecker(c.id)}
                              className="text-red-400 hover:text-red-600 transition-colors p-2"
                            >
                              <Trash2 size={18} />
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        );

      case 'branches':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-bold text-slate-800">Gerenciamento de Filiais</h3>
              <button 
                onClick={() => setShowAddBranch(true)}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700 shadow-md transition-all active:scale-95"
              >
                <MapPin size={18} />
                Nova Filial
              </button>
            </div>

            {showAddBranch && (
              <div className="bg-emerald-50 p-6 rounded-xl border border-emerald-200 shadow-inner">
                <form onSubmit={handleAddBranch} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                  <div>
                    <label className="block text-xs font-bold text-emerald-700 uppercase mb-1">Nome da Filial</label>
                    <input 
                      type="text" 
                      required
                      className="w-full px-4 py-2 border border-emerald-200 rounded-lg outline-none focus:ring-2 focus:ring-emerald-500"
                      value={newBranch.name}
                      onChange={e => setNewBranch({...newBranch, name: e.target.value})}
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-emerald-700 uppercase mb-1">Código</label>
                    <input 
                      type="text" 
                      required
                      className="w-full px-4 py-2 border border-emerald-200 rounded-lg outline-none focus:ring-2 focus:ring-emerald-500"
                      value={newBranch.code}
                      onChange={e => setNewBranch({...newBranch, code: e.target.value})}
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-emerald-700 uppercase mb-1">Cidade / UF</label>
                    <input 
                      type="text" 
                      placeholder="Ex: São Paulo - SP"
                      className="w-full px-4 py-2 border border-emerald-200 rounded-lg outline-none focus:ring-2 focus:ring-emerald-500"
                      value={newBranch.city}
                      onChange={e => setNewBranch({...newBranch, city: e.target.value})}
                    />
                  </div>
                  <div className="flex items-end gap-2">
                    <button type="submit" className="flex-1 py-2 bg-emerald-600 text-white font-bold rounded-lg hover:bg-emerald-700 flex items-center justify-center gap-2">
                      <Check size={18} /> Salvar
                    </button>
                    <button type="button" onClick={() => setShowAddBranch(false)} className="px-4 py-2 bg-white text-slate-600 border border-slate-200 font-bold rounded-lg hover:bg-slate-50">
                      <X size={18} />
                    </button>
                  </div>
                </form>
              </div>
            )}

            <div className="bg-white rounded-xl border border-slate-200 overflow-hidden shadow-sm">
              <div className="overflow-x-auto">
                <table className="w-full text-left min-w-[600px]">
                  <thead className="bg-slate-50 text-xs font-bold text-slate-500 uppercase">
                    <tr>
                      <th className="px-6 py-4">Código</th>
                      <th className="px-6 py-4">Nome da Filial</th>
                      <th className="px-6 py-4">Localização</th>
                      <th className="px-6 py-4 text-center">Ações</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {branches.map(b => (
                      <tr key={b.id}>
                        <td className="px-6 py-4 font-bold text-slate-600">{b.code}</td>
                        <td className="px-6 py-4 font-medium">{b.name}</td>
                        <td className="px-6 py-4 text-slate-500">{b.city || 'Não inf.'}</td>
                        <td className="px-6 py-4 text-center">
                          <button 
                            onClick={() => deleteBranch(b.id)}
                            className="text-red-400 hover:text-red-600 p-2 transition-colors"
                          >
                            <Trash2 size={18} />
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        );

      case 'cds':
        return (
          <div className="max-w-3xl space-y-6">
            <div className="flex justify-between items-center">
               <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                 <Warehouse className="text-blue-600" />
                 Centros de Distribuição (CD)
               </h3>
               <button 
                onClick={() => setShowAddCD(true)}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700 shadow-md transition-all active:scale-95"
               >
                 <Plus size={18} />
                 Novo CD
               </button>
            </div>

            {showAddCD && (
              <div className="bg-slate-100 p-6 rounded-xl border border-slate-200 shadow-inner">
                <form onSubmit={handleAddCD} className="flex flex-col md:flex-row gap-4">
                  <div className="flex-1">
                    <label className="block text-xs font-bold text-slate-700 uppercase mb-1">Nome do CD</label>
                    <input 
                      type="text" 
                      required
                      className="w-full px-4 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                      value={newCD.name}
                      onChange={e => setNewCD({...newCD, name: e.target.value})}
                    />
                  </div>
                  <div className="md:w-48">
                    <label className="block text-xs font-bold text-slate-700 uppercase mb-1">Código</label>
                    <input 
                      type="text" 
                      required
                      className="w-full px-4 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                      value={newCD.code}
                      onChange={e => setNewCD({...newCD, code: e.target.value})}
                    />
                  </div>
                  <div className="flex items-end gap-2">
                    <button type="submit" className="px-6 py-2 bg-blue-600 text-white font-bold rounded-lg hover:bg-blue-700 flex items-center gap-2">
                      <Check size={18} /> Salvar
                    </button>
                    <button type="button" onClick={() => setShowAddCD(false)} className="px-4 py-2 bg-white text-slate-600 border border-slate-200 font-bold rounded-lg hover:bg-slate-50">
                      <X size={18} />
                    </button>
                  </div>
                </form>
              </div>
            )}

            <div className="space-y-4">
               {cds.map(cd => (
                 <div key={cd.id} className="p-4 bg-white rounded-xl border border-slate-200 shadow-sm flex items-center justify-between group hover:border-blue-300 transition-all">
                   <div className="flex items-center gap-4">
                     <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
                       <Warehouse size={24} />
                     </div>
                     <div>
                       <p className="font-bold text-slate-800">{cd.name}</p>
                       <p className="text-sm text-slate-500 font-mono">Código: {cd.code}</p>
                     </div>
                   </div>
                   <div className="flex items-center gap-3">
                      <span className="hidden sm:inline-block px-3 py-1 bg-emerald-100 text-emerald-700 rounded text-[10px] font-bold">OPERANTE</span>
                      <button 
                        onClick={() => deleteCD(cd.id, cd.name)}
                        className="p-3 text-red-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors border border-transparent hover:border-red-100"
                        title="Excluir Centro de Distribuição"
                      >
                        <Trash2 size={20} />
                      </button>
                   </div>
                 </div>
               ))}
               {cds.length === 0 && (
                 <div className="text-center p-12 bg-slate-50 border border-dashed border-slate-300 rounded-xl text-slate-400">
                   Nenhum Centro de Distribuição cadastrado.
                 </div>
               )}
            </div>
          </div>
        );

      default:
        return <div>Em breve...</div>;
    }
  };

  return (
    <Layout 
      user={user} 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      onLogout={handleLogout}
    >
      {renderContent()}
    </Layout>
  );
};

