import { jsPDF } from 'jspdf';
import QRCode from 'qrcode';
import JsBarcode from 'jsbarcode';
import { Manifest, LoadingManifest } from '../types';

export const generateManifestPDF = async (manifest: Manifest, isPreview: boolean = false): Promise<string | null> => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4',
  });

  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();

  for (let i = 1; i <= manifest.palletsCount; i++) {
    if (i > 1) doc.addPage();
    doc.setLineWidth(0.5);
    doc.rect(10, 10, pageWidth - 20, pageHeight - 20);
    doc.setFontSize(10);
    doc.text('MANIFESTO DE CONFERÊNCIA', pageWidth / 2, 20, { align: 'center' });
    doc.setFontSize(48);
    doc.setFont('helvetica', 'bold');
    doc.text(manifest.manifestNumber, pageWidth / 2, 40, { align: 'center' });
    const canvas = document.createElement('canvas');
    JsBarcode(canvas, manifest.manifestNumber, { format: 'CODE128', width: 2, height: 60, displayValue: false });
    doc.addImage(canvas.toDataURL('image/png'), 'PNG', (pageWidth - 100) / 2, 45, 100, 20);
    doc.setLineWidth(0.2);
    doc.line(15, 70, pageWidth - 15, 70);
    doc.setFontSize(14);
    doc.setFont('helvetica', 'normal');
    doc.text('DESTINO:', 20, 85);
    doc.setFontSize(28);
    doc.setFont('helvetica', 'bold');
    doc.text(manifest.branchName, 20, 98);
    doc.setFontSize(12);
    doc.setFont('helvetica', 'normal');
    doc.text(`ORIGEM (CD): ${manifest.cdName} (${manifest.cdId})`, 20, 110);
    doc.text(`DATA: ${new Date(manifest.conferenceDate).toLocaleDateString('pt-BR')}`, 20, 125);
    doc.text(`CONFERENTE: ${manifest.checkerName}`, 20, 132);
    doc.setFontSize(14);
    doc.text('PALETE:', pageWidth - 60, 125);
    doc.setFontSize(42);
    doc.setFont('helvetica', 'bold');
    doc.text(`${i}/${manifest.palletsCount}`, pageWidth - 60, 145);
    doc.setFontSize(12);
    doc.text('PEDIDOS NESTE MANIFESTO:', 20, 160);
    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    const splitOrders = doc.splitTextToSize(manifest.orders, pageWidth - 40);
    doc.text(splitOrders, 20, 168);
    const qrContent = JSON.stringify({ m: manifest.manifestNumber, p: `${i}/${manifest.palletsCount}` });
    doc.addImage(await QRCode.toDataURL(qrContent), 'PNG', pageWidth - 50, 160, 30, 30);
    doc.text(`Gerado em: ${new Date().toLocaleString('pt-BR')}`, 20, pageHeight - 15);
  }

  if (isPreview) {
    const blob = doc.output('blob');
    return URL.createObjectURL(blob);
  } else {
    doc.save(`Etiquetas_${manifest.manifestNumber}.pdf`);
    return null;
  }
};

export const generateLoadingManifestPDF = async (data: LoadingManifest, isPreview: boolean = false): Promise<string | null> => {
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
  const pageWidth = doc.internal.pageSize.getWidth();

  // Header
  doc.setFillColor(30, 41, 59);
  doc.rect(0, 0, pageWidth, 40, 'F');
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(20);
  doc.setFont('helvetica', 'bold');
  doc.text('MANIFESTO DE CARGA / ROMANEIO', 15, 18);
  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.text(`Nº MANIFESTO: ${data.manifestNumber}`, 15, 28);
  doc.text(`DATA EMISSÃO: ${new Date(data.createdAt).toLocaleString('pt-BR')}`, 15, 34);

  // QR Code Header
  const qrHeader = await QRCode.toDataURL(data.manifestNumber);
  doc.addImage(qrHeader, 'PNG', pageWidth - 45, 5, 30, 30);

  // Section 1: Origem e Destino
  doc.setTextColor(0, 0, 0);
  doc.setFontSize(12);
  doc.setFont('helvetica', 'bold');
  doc.text('1. INFORMAÇÕES DA VIAGEM', 15, 50);
  doc.line(15, 52, pageWidth - 15, 52);

  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.text(`UNIDADE ORIGEM: ${data.cdName}`, 15, 60);
  doc.text(`FILIAL DESTINO: ${data.branchName}`, 15, 66);
  doc.text(`DATA PREVISTA ENTREGA: ${new Date(data.deliveryDate).toLocaleDateString('pt-BR')}`, 15, 72);
  doc.text(`NÚMERO DO LACRE: ${data.sealNumber || 'NÃO INFORMADO'}`, 15, 78);

  // Section 2: Transporte
  doc.setFontSize(12);
  doc.setFont('helvetica', 'bold');
  doc.text('2. DADOS DO TRANSPORTE', 15, 90);
  doc.line(15, 92, pageWidth - 15, 92);

  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.text(`MOTORISTA: ${data.driverName}`, 15, 100);
  doc.text(`VEÍCULO (PLACA): ${data.vehiclePlate}`, 15, 106);
  doc.text(`EMITIDO POR: ${data.createdBy}`, 15, 112);

  // Section 3: Notas Fiscais (Table)
  doc.setFontSize(12);
  doc.setFont('helvetica', 'bold');
  doc.text('3. RELAÇÃO DE NOTAS FISCAIS', 15, 125);
  doc.line(15, 127, pageWidth - 15, 127);

  // Table Header
  doc.setFillColor(241, 245, 249);
  doc.rect(15, 132, pageWidth - 30, 8, 'F');
  doc.setFontSize(9);
  doc.text('ÍNDICE', 20, 137);
  doc.text('NÚMERO NF', 40, 137);
  doc.text('CHAVE DE ACESSO', 70, 137);

  let y = 145;
  data.invoices.forEach((inv, index) => {
    if (y > 270) {
      doc.addPage();
      y = 20;
    }
    doc.setFont('helvetica', 'normal');
    doc.text(`${index + 1}`, 20, y);
    doc.setFont('helvetica', 'bold');
    doc.text(inv.number, 40, y);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(7);
    doc.text(inv.key, 70, y);
    doc.setFontSize(9);
    doc.setDrawColor(200, 200, 200);
    doc.line(15, y + 2, pageWidth - 15, y + 2);
    y += 8;
  });

  // Footer / Signatures
  const footerY = 270;
  doc.line(20, footerY, 80, footerY);
  doc.text('ASSINATURA EXPEDIÇÃO', 30, footerY + 5);
  doc.line(pageWidth - 80, footerY, pageWidth - 20, footerY);
  doc.text('ASSINATURA MOTORISTA', pageWidth - 70, footerY + 5);

  if (isPreview) {
    const blob = doc.output('blob');
    return URL.createObjectURL(blob);
  } else {
    doc.save(`Manifesto_Carga_${data.manifestNumber}.pdf`);
    return null;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  Truck, 
  Scan, 
  Trash2, 
  AlertCircle, 
  CheckCircle2, 
  FileDown, 
  Eye,
  Loader2,
  X,
  ExternalLink,
  Download
} from 'lucide-react';
import { 
  Driver, 
  Vehicle, 
  Branch, 
  DistributionCenter, 
  LoadingManifest, 
  InvoiceItem 
} from '../types';
import { generateLoadingManifestPDF } from '../services/pdfGenerator';

interface LoadingManifestFormProps {
  drivers: Driver[];
  vehicles: Vehicle[];
  branches: Branch[];
  cds: DistributionCenter[];
  onSave: (m: LoadingManifest) => void;
  currentUser: { name: string; uid: string };
}

const LoadingManifestForm: React.FC<LoadingManifestFormProps> = ({ 
  drivers, 
  vehicles, 
  branches, 
  cds, 
  onSave,
  currentUser
}) => {
  const [formData, setFormData] = useState({
    manifestNumber: `MC-${Date.now().toString().substr(-6)}`,
    cdId: cds[0]?.id || '',
    branchId: '',
    driverId: '',
    vehicleId: '',
    sealNumber: '',
    deliveryDate: new Date().toISOString().split('T')[0],
  });

  const [invoices, setInvoices] = useState<InvoiceItem[]>([]);
  const [scannerInput, setScannerInput] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const scannerRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    return () => { if (previewUrl) URL.revokeObjectURL(previewUrl); };
  }, [previewUrl]);

  const activeDrivers = drivers.filter(d => d.status === 'ATIVO');
  const activeVehicles = vehicles.filter(v => v.status === 'ATIVO');
  const activeBranches = branches.filter(b => b.status === 'ATIVO');

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    const val = scannerInput.trim();
    if (val.length !== 44 || !/^\d+$/.test(val)) {
      setError("Chave de acesso inválida! Deve conter exatamente 44 dígitos numéricos.");
      setScannerInput('');
      return;
    }

    if (invoices.some(i => i.key === val)) {
      setError("Esta Nota Fiscal já foi bipada neste manifesto.");
      setScannerInput('');
      return;
    }

    // Extract NF number: positions 26 to 34 (9 digits)
    const nfNumber = val.substring(25, 34);

    setInvoices([{ key: val, number: nfNumber }, ...invoices]);
    setScannerInput('');
    scannerRef.current?.focus();
  };

  const removeInvoice = (key: string) => {
    setInvoices(invoices.filter(i => i.key !== key));
  };

  const validate = () => {
    if (!formData.branchId) return "Selecione a filial de destino";
    if (!formData.driverId) return "Selecione o motorista";
    if (!formData.vehicleId) return "Selecione o veículo";
    if (invoices.length === 0) return "Bipe pelo menos uma Nota Fiscal";
    return null;
  };

  const constructManifest = (): LoadingManifest => {
    const cd = cds.find(c => c.id === formData.cdId);
    const branch = branches.find(b => b.id === formData.branchId);
    const driver = drivers.find(d => d.id === formData.driverId);
    const vehicle = vehicles.find(v => v.id === formData.vehicleId);

    return {
      id: `lm_${Date.now()}`,
      ...formData,
      invoices,
      createdAt: new Date().toISOString(),
      createdBy: currentUser.name,
      cdName: cd?.name || '',
      branchName: branch?.name || '',
      driverName: driver?.name || '',
      vehiclePlate: vehicle?.plate || ''
    };
  };

  const handlePreview = async () => {
    const err = validate();
    if (err) { setError(err); return; }
    setIsGenerating(true);
    try {
      const m = constructManifest();
      const url = await generateLoadingManifestPDF(m, true);
      setPreviewUrl(url);
    } catch (e) { setError("Erro ao gerar PDF."); }
    finally { setIsGenerating(false); }
  };

  const handleSave = async () => {
    const err = validate();
    if (err) { setError(err); return; }
    setIsGenerating(true);
    try {
      const m = constructManifest();
      await generateLoadingManifestPDF(m, false);
      onSave(m);
      // Reset
      setInvoices([]);
      setFormData({ ...formData, manifestNumber: `MC-${Date.now().toString().substr(-6)}`, sealNumber: '' });
    } catch (e) { setError("Erro ao salvar manifesto."); }
    finally { setIsGenerating(false); }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6">
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 bg-slate-800 text-white flex items-center gap-3">
          <Truck />
          <h2 className="font-bold">Gerar Manifesto de Carga (Embarque)</h2>
        </div>

        <div className="p-6 grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Form Side */}
          <div className="space-y-4 lg:col-span-1 border-r border-slate-100 pr-0 lg:pr-8">
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Unidade de Origem</label>
              <select 
                className="w-full p-2 border rounded bg-slate-50"
                value={formData.cdId}
                onChange={e => setFormData({...formData, cdId: e.target.value})}
              >
                {cds.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Filial de Destino *</label>
              <select 
                className="w-full p-2 border rounded"
                value={formData.branchId}
                onChange={e => setFormData({...formData, branchId: e.target.value})}
              >
                <option value="">Selecione...</option>
                {activeBranches.map(b => <option key={b.id} value={b.id}>{b.name} ({b.code})</option>)}
              </select>
            </div>

            <div className="grid grid-cols-2 gap-4">
               <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Motorista *</label>
                <select 
                  className="w-full p-2 border rounded"
                  value={formData.driverId}
                  onChange={e => setFormData({...formData, driverId: e.target.value})}
                >
                  <option value="">Selecione...</option>
                  {activeDrivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Veículo *</label>
                <select 
                  className="w-full p-2 border rounded"
                  value={formData.vehicleId}
                  onChange={e => setFormData({...formData, vehicleId: e.target.value})}
                >
                  <option value="">Selecione...</option>
                  {activeVehicles.map(v => <option key={v.id} value={v.id}>{v.plate} - {v.model}</option>)}
                </select>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Nº Lacre</label>
                <input 
                  type="text" 
                  className="w-full p-2 border rounded"
                  value={formData.sealNumber}
                  onChange={e => setFormData({...formData, sealNumber: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Data Entrega *</label>
                <input 
                  type="date" 
                  className="w-full p-2 border rounded"
                  value={formData.deliveryDate}
                  onChange={e => setFormData({...formData, deliveryDate: e.target.value})}
                />
              </div>
            </div>

            <div className="pt-4 space-y-3">
              <button 
                onClick={handlePreview}
                className="w-full py-3 bg-slate-100 text-slate-700 font-bold rounded-lg hover:bg-slate-200 flex items-center justify-center gap-2"
              >
                <Eye size={18} /> Visualizar
              </button>
              <button 
                onClick={handleSave}
                disabled={isGenerating}
                className="w-full py-3 bg-blue-600 text-white font-bold rounded-lg hover:bg-blue-700 shadow-lg shadow-blue-200 flex items-center justify-center gap-2"
              >
                {isGenerating ? <Loader2 className="animate-spin" /> : <FileDown size={18} />}
                Gerar Manifesto
              </button>
            </div>
          </div>

          {/* Scanner Side */}
          <div className="lg:col-span-2 space-y-6">
            <form onSubmit={handleScan} className="bg-blue-50 p-6 rounded-xl border border-blue-100">
              <div className="flex items-center gap-3 mb-4">
                <Scan className="text-blue-600" />
                <h3 className="font-bold text-blue-900 uppercase text-sm tracking-widest">Bipagem de Notas Fiscais</h3>
              </div>
              <div className="relative">
                <input 
                  ref={scannerRef}
                  type="text"
                  placeholder="Bipe a Chave de Acesso (44 dígitos)..."
                  className="w-full p-4 pr-16 border-2 border-blue-200 rounded-xl focus:ring-4 focus:ring-blue-100 outline-none text-lg font-mono tracking-tighter"
                  value={scannerInput}
                  onChange={e => setScannerInput(e.target.value)}
                  autoFocus
                />
                <button 
                  type="submit"
                  className="absolute right-2 top-2 bottom-2 px-4 bg-blue-600 text-white rounded-lg font-bold"
                >
                  OK
                </button>
              </div>
              {error && (
                <div className="mt-3 flex items-center gap-2 text-red-600 text-xs font-bold bg-white p-2 rounded border border-red-100">
                  <AlertCircle size={14} /> {error}
                </div>
              )}
            </form>

            <div className="bg-white border rounded-xl overflow-hidden">
              <div className="p-3 bg-slate-50 border-b flex justify-between items-center">
                <span className="text-xs font-bold text-slate-500 uppercase">Itens Bipados ({invoices.length})</span>
                {invoices.length > 0 && (
                  <button 
                    onClick={() => setInvoices([])}
                    className="text-[10px] font-bold text-red-500 hover:underline"
                  >
                    Limpar Tudo
                  </button>
                )}
              </div>
              <div className="max-h-[400px] overflow-y-auto">
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50/50 text-[10px] font-bold text-slate-400 uppercase">
                    <tr>
                      <th className="px-4 py-2">NF</th>
                      <th className="px-4 py-2">Chave de Acesso</th>
                      <th className="px-4 py-2 text-right">Ação</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y">
                    {invoices.map((inv) => (
                      <tr key={inv.key} className="hover:bg-slate-50 group">
                        <td className="px-4 py-3 font-bold text-blue-600">{inv.number}</td>
                        <td className="px-4 py-3 text-slate-500 font-mono text-[11px] truncate max-w-[300px]">{inv.key}</td>
                        <td className="px-4 py-3 text-right">
                          <button 
                            onClick={() => removeInvoice(inv.key)}
                            className="p-1.5 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded"
                          >
                            <Trash2 size={16} />
                          </button>
                        </td>
                      </tr>
                    ))}
                    {invoices.length === 0 && (
                      <tr>
                        <td colSpan={3} className="px-4 py-20 text-center text-slate-400 italic">
                          Aguardando bipagem das notas...
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Preview Modal */}
      {previewUrl && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-5xl h-[90vh] rounded-2xl flex flex-col overflow-hidden">
            <div className="p-4 border-b flex justify-between items-center">
              <h3 className="font-bold flex items-center gap-2"><Eye size={18} /> Pré-visualização do Manifesto</h3>
              <button onClick={() => setPreviewUrl(null)} className="p-2 hover:bg-slate-100 rounded-full"><X /></button>
            </div>
            <div className="flex-1 bg-slate-100 p-4">
              <object data={previewUrl} type="application/pdf" className="w-full h-full rounded shadow-inner" />
            </div>
            <div className="p-4 flex justify-end gap-3 border-t">
              <button onClick={() => setPreviewUrl(null)} className="px-6 py-2 bg-slate-200 font-bold rounded">Fechar</button>
              <button 
                onClick={() => {
                   const link = document.createElement('a');
                   link.href = previewUrl;
                   link.download = `Manifesto_Carga_${formData.manifestNumber}.pdf`;
                   link.click();
                }}
                className="px-6 py-2 bg-blue-600 text-white font-bold rounded flex items-center gap-2"
              >
                <Download size={18} /> Baixar Agora
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

