    return saved ? JSON.parse(saved) : null;
  });

  const [manifests, setManifests] = useState<Manifest[]>(() => {
    const saved = localStorage.getItem('logi_manifests');
    return saved ? JSON.parse(saved) : [];
  });

  const [loadingManifests, setLoadingManifests] = useState<LoadingManifest[]>(() => {
    const saved = localStorage.getItem('logi_loading_manifests');
    return saved ? JSON.parse(saved) : [];
  });

  const [checkers, setCheckers] = useState<Checker[]>(() => {
    const saved = localStorage.getItem('logi_checkers');
    return saved ? JSON.parse(saved) : INITIAL_CHECKERS;
  });

  const [drivers, setDrivers] = useState<Driver[]>(() => {
    const saved = localStorage.getItem('logi_drivers');
    return saved ? JSON.parse(saved) : [];
  });

  const [vehicles, setVehicles] = useState<Vehicle[]>(() => {
    const saved = localStorage.getItem('logi_vehicles');
    return saved ? JSON.parse(saved) : [];
  });

  const [branches, setBranches] = useState<Branch[]>(() => {
    const saved = localStorage.getItem('logi_branches');
    return saved ? JSON.parse(saved) : INITIAL_BRANCHES;
  });

  const [cds, setCds] = useState<DistributionCenter[]>(() => {
    const saved = localStorage.getItem('logi_cds');
    return saved ? JSON.parse(saved) : INITIAL_CDS;
  });

  // UI States
  const [loginForm, setLoginForm] = useState({ email: '', password: '' });
  const [loginError, setLoginError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [searchTerm, setSearchTerm] = useState('');

  const [showAddChecker, setShowAddChecker] = useState(false);
  const [showAddDriver, setShowAddDriver] = useState(false);
  const [showAddVehicle, setShowAddVehicle] = useState(false);
  const [showAddBranch, setShowAddBranch] = useState(false);
  const [showAddCD, setShowAddCD] = useState(false);

  const [newChecker, setNewChecker] = useState({ name: '', externalId: '' });
  const [newDriver, setNewDriver] = useState({ name: '', document: '', phone: '' });
  const [newVehicle, setNewVehicle] = useState({ plate: '', model: '', type: 'TRUCK' });
  const [newBranch, setNewBranch] = useState({ name: '', code: '', city: '', state: '' });
  const [newCD, setNewCD] = useState({ name: '', code: '' });

  useEffect(() => { localStorage.setItem('logi_manifests', JSON.stringify(manifests)); }, [manifests]);
  useEffect(() => { localStorage.setItem('logi_loading_manifests', JSON.stringify(loadingManifests)); }, [loadingManifests]);
  useEffect(() => { localStorage.setItem('logi_checkers', JSON.stringify(checkers)); }, [checkers]);
  useEffect(() => { localStorage.setItem('logi_drivers', JSON.stringify(drivers)); }, [drivers]);
  useEffect(() => { localStorage.setItem('logi_vehicles', JSON.stringify(vehicles)); }, [vehicles]);
  useEffect(() => { localStorage.setItem('logi_branches', JSON.stringify(branches)); }, [branches]);
  useEffect(() => { localStorage.setItem('logi_cds', JSON.stringify(cds)); }, [cds]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError(null);
    const emailInput = loginForm.email.toLowerCase();
    const passwordInput = loginForm.password;
    if ((emailInput === 'diego.silva' || emailInput === 'diego.silva@logi.com') && passwordInput === '05171888302') {
      const u: UserProfile = { uid: 'u_diego', email: 'diego.silva@logi.com', name: 'Diego Silva', role: 'ADMIN' };
      setUser(u);
      localStorage.setItem('logi_user', JSON.stringify(u));
    } else {
      setLoginError('Credenciais inválidas.');
    }
  };

  const handleLogout = () => { setUser(null); localStorage.removeItem('logi_user'); };

  const addChecker = () => {
    if (newChecker.name) {
      setCheckers([...checkers, { id: `c_${Date.now()}`, ...newChecker, status: 'ATIVO' }]);
      setNewChecker({ name: '', externalId: '' });
      setShowAddChecker(false);
    }
  };

  const addDriver = () => {
    if (newDriver.name) {
      setDrivers([...drivers, { id: `d_${Date.now()}`, ...newDriver, status: 'ATIVO' }]);
      setNewDriver({ name: '', document: '', phone: '' });
      setShowAddDriver(false);
    }
  };

  const addVehicle = () => {
    if (newVehicle.plate) {
      setVehicles([...vehicles, { id: `v_${Date.now()}`, ...newVehicle, status: 'ATIVO' }]);
      setNewVehicle({ plate: '', model: '', type: 'TRUCK' });
      setShowAddVehicle(false);
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-100 p-4 font-inter">
        <div className="max-w-md w-full bg-white rounded-2xl shadow-xl overflow-hidden">
          <div className="bg-slate-900 p-8 text-center text-white">
             <Warehouse size={40} className="mx-auto mb-4 text-blue-500" />
             <h1 className="text-2xl font-bold tracking-tighter">LogiLabel Pro</h1>
             <p className="text-slate-400 text-sm">Controle de Expedição & Cargas</p>
          </div>
          <form onSubmit={handleLogin} className="p-8 space-y-4">
             {loginError && <div className="p-3 bg-red-50 text-red-600 text-xs rounded border border-red-100">{loginError}</div>}
             <input className="w-full p-3 border rounded-xl" type="text" placeholder="Usuário" value={loginForm.email} onChange={e => setLoginForm({...loginForm, email: e.target.value})} required />
             <input className="w-full p-3 border rounded-xl" type="password" placeholder="Senha" value={loginForm.password} onChange={e => setLoginForm({...loginForm, password: e.target.value})} required />
             <button type="submit" className="w-full py-3 bg-blue-600 text-white font-bold rounded-xl shadow-lg shadow-blue-200">Entrar</button>
          </form>
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard manifests={manifests} />;
      case 'generate': return <ManifestForm checkers={checkers} branches={branches} cds={cds} onSave={m => setManifests([m, ...manifests])} currentUser={user} />;
      case 'loading-manifest': return <LoadingManifestForm drivers={drivers} vehicles={vehicles} branches={branches} cds={cds} onSave={m => setLoadingManifests([m, ...loadingManifests])} currentUser={user} />;
      case 'checkers': 
        return (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-bold">Conferentes</h3>
              <button onClick={() => setShowAddChecker(true)} className="px-4 py-2 bg-blue-600 text-white rounded-lg flex items-center gap-2"><UserPlus size={18}/> Novo</button>
            </div>
            {showAddChecker && (
              <div className="p-4 bg-white border rounded-xl flex gap-3">
                <input placeholder="Nome" className="flex-1 p-2 border rounded" value={newChecker.name} onChange={e => setNewChecker({...newChecker, name: e.target.value})} />
                <input placeholder="ID Crachá" className="w-32 p-2 border rounded" value={newChecker.externalId} onChange={e => setNewChecker({...newChecker, externalId: e.target.value})} />
                <button onClick={addChecker} className="bg-blue-600 text-white px-4 rounded">Salvar</button>
              </div>
            )}
            <div className="bg-white rounded-xl border overflow-hidden">
               <table className="w-full text-left">
                  <thead className="bg-slate-50 text-xs font-bold uppercase text-slate-500"><tr className="border-b">
                    <th className="p-4">Nome</th><th className="p-4">ID</th><th className="p-4">Ação</th>
                  </tr></thead>
                  <tbody>{checkers.map(c => <tr key={c.id} className="border-b">
                    <td className="p-4">{c.name}</td><td className="p-4">{c.externalId}</td>
                    <td className="p-4"><button onClick={() => setCheckers(checkers.filter(x => x.id !== c.id))} className="text-red-500"><Trash2 size={16}/></button></td>
                  </tr>)}</tbody>
               </table>
            </div>
          </div>
        );
      case 'drivers':
        return (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-bold">Cadastro de Motoristas</h3>
              <button onClick={() => setShowAddDriver(true)} className="px-4 py-2 bg-blue-600 text-white rounded-lg flex items-center gap-2"><Plus size={18}/> Novo Motorista</button>
            </div>
            {showAddDriver && (
              <div className="p-4 bg-white border rounded-xl flex flex-wrap gap-3">
                <input placeholder="Nome Completo" className="flex-1 min-w-[200px] p-2 border rounded" value={newDriver.name} onChange={e => setNewDriver({...newDriver, name: e.target.value})} />
                <input placeholder="CNH / CPF" className="w-48 p-2 border rounded" value={newDriver.document} onChange={e => setNewDriver({...newDriver, document: e.target.value})} />
                <input placeholder="Telefone" className="w-48 p-2 border rounded" value={newDriver.phone} onChange={e => setNewDriver({...newDriver, phone: e.target.value})} />
                <button onClick={addDriver} className="bg-blue-600 text-white px-4 py-2 rounded">Salvar</button>
                <button onClick={() => setShowAddDriver(false)} className="bg-slate-200 px-4 py-2 rounded">Cancelar</button>
              </div>
            )}
            <div className="bg-white rounded-xl border overflow-hidden shadow-sm">
               <table className="w-full text-left">
                  <thead className="bg-slate-50 text-xs font-bold uppercase text-slate-500"><tr className="border-b">
                    <th className="p-4">Nome</th><th className="p-4">Documento</th><th className="p-4">Telefone</th><th className="p-4">Ação</th>
                  </tr></thead>
                  <tbody>{drivers.map(d => <tr key={d.id} className="border-b hover:bg-slate-50">
                    <td className="p-4 font-bold">{d.name}</td><td className="p-4">{d.document}</td><td className="p-4">{d.phone}</td>
                    <td className="p-4"><button onClick={() => setDrivers(drivers.filter(x => x.id !== d.id))} className="text-red-400 hover:text-red-600"><Trash2 size={18}/></button></td>
                  </tr>)}</tbody>
               </table>
               {drivers.length === 0 && <div className="p-10 text-center text-slate-400">Nenhum motorista cadastrado.</div>}
            </div>
          </div>
        );
      case 'vehicles':
        return (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-bold">Cadastro de Veículos</h3>
              <button onClick={() => setShowAddVehicle(true)} className="px-4 py-2 bg-blue-600 text-white rounded-lg flex items-center gap-2"><Plus size={18}/> Novo Veículo</button>
            </div>
            {showAddVehicle && (
              <div className="p-4 bg-white border rounded-xl flex flex-wrap gap-3">
                <input placeholder="Placa (Ex: ABC1D23)" className="w-40 p-2 border rounded" value={newVehicle.plate} onChange={e => setNewVehicle({...newVehicle, plate: e.target.value.toUpperCase()})} />
                <input placeholder="Modelo / Marca" className="flex-1 min-w-[200px] p-2 border rounded" value={newVehicle.model} onChange={e => setNewVehicle({...newVehicle, model: e.target.value})} />
                <select className="w-40 p-2 border rounded" value={newVehicle.type} onChange={e => setNewVehicle({...newVehicle, type: e.target.value})}>
                   <option value="TRUCK">TRUCK</option><option value="TOCO">TOCO</option><option value="VAN">VAN</option><option value="3/4">3/4</option>
                </select>
                <button onClick={addVehicle} className="bg-blue-600 text-white px-4 py-2 rounded">Salvar</button>
                <button onClick={() => setShowAddVehicle(false)} className="bg-slate-200 px-4 py-2 rounded">Cancelar</button>
              </div>
            )}
            <div className="bg-white rounded-xl border overflow-hidden shadow-sm">
               <table className="w-full text-left">
                  <thead className="bg-slate-50 text-xs font-bold uppercase text-slate-500"><tr className="border-b">
                    <th className="p-4">Placa</th><th className="p-4">Modelo</th><th className="p-4">Tipo</th><th className="p-4">Ação</th>
                  </tr></thead>
                  <tbody>{vehicles.map(v => <tr key={v.id} className="border-b hover:bg-slate-50">
                    <td className="p-4 font-mono font-bold text-blue-600">{v.plate}</td><td className="p-4">{v.model}</td><td className="p-4"><span className="px-2 py-0.5 bg-slate-100 rounded text-[10px] font-bold">{v.type}</span></td>
                    <td className="p-4"><button onClick={() => setVehicles(vehicles.filter(x => x.id !== v.id))} className="text-red-400 hover:text-red-600"><Trash2 size={18}/></button></td>
                  </tr>)}</tbody>
               </table>
               {vehicles.length === 0 && <div className="p-10 text-center text-slate-400">Nenhum veículo cadastrado.</div>}
            </div>
          </div>
        );
      case 'history':
        return (
          <div className="space-y-6">
             <div className="flex gap-4">
                <div className="flex-1 relative">
                  <Search className="absolute left-3 top-2.5 text-slate-400" size={18} />
                  <input className="w-full pl-10 pr-4 py-2 border rounded-lg" placeholder="Buscar manifestos..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                </div>
             </div>
             <div className="grid grid-cols-1 gap-6">
                <div className="bg-white rounded-xl border shadow-sm overflow-hidden">
                  <div className="p-4 bg-slate-50 border-b font-bold text-xs uppercase text-slate-500">Histórico de Etiquetas</div>
                  <table className="w-full text-left text-sm">
                    <thead><tr className="border-b bg-slate-50/50">
                      <th className="p-3">Manifesto</th><th className="p-3">Destino</th><th className="p-3 text-center">Ações</th>
                    </tr></thead>
                    <tbody>{manifests.filter(m => m.manifestNumber.includes(searchTerm)).map(m => (
                      <tr key={m.id} className="border-b">
                        <td className="p-3 font-bold">{m.manifestNumber}</td><td className="p-3">{m.branchName}</td>
                        <td className="p-3 text-center flex justify-center gap-2">
                          <button onClick={() => generateManifestPDF(m)} className="p-2 text-blue-600 hover:bg-blue-50 rounded"><Printer size={16}/></button>
                          <button onClick={() => setManifests(manifests.filter(x => x.id !== m.id))} className="p-2 text-red-500 hover:bg-red-50 rounded"><Trash2 size={16}/></button>
                        </td>
                      </tr>
                    ))}</tbody>
                  </table>
                </div>

                <div className="bg-white rounded-xl border shadow-sm overflow-hidden">
                  <div className="p-4 bg-slate-800 text-white font-bold text-xs uppercase">Histórico de Manifestos de Carga</div>
                  <table className="w-full text-left text-sm">
                    <thead><tr className="border-b bg-slate-50/50">
                      <th className="p-3">Nº Carga</th><th className="p-3">Placa / Motorista</th><th className="p-3">Destino</th><th className="p-3 text-center">Ações</th>
                    </tr></thead>
                    <tbody>{loadingManifests.filter(m => m.manifestNumber.includes(searchTerm)).map(m => (
                      <tr key={m.id} className="border-b">
                        <td className="p-3 font-bold text-blue-600">{m.manifestNumber}</td>
                        <td className="p-3">
                           <div className="font-bold">{m.vehiclePlate}</div>
                           <div className="text-[10px] text-slate-400">{m.driverName}</div>
                        </td>
                        <td className="p-3">{m.branchName}</td>
                        <td className="p-3 text-center flex justify-center gap-2">
                          <button onClick={() => generateLoadingManifestPDF(m)} className="p-2 text-blue-600 hover:bg-blue-50 rounded"><Printer size={16}/></button>
                          <button onClick={() => setLoadingManifests(loadingManifests.filter(x => x.id !== m.id))} className="p-2 text-red-500 hover:bg-red-50 rounded"><Trash2 size={16}/></button>
                        </td>
                      </tr>
                    ))}</tbody>
                  </table>
                </div>
             </div>
          </div>
        );
      default: return <Dashboard manifests={manifests} />;
    }
  };

  return (
    <Layout user={user} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { 
  LayoutDashboard, 
  PlusCircle, 
  History, 
  LogOut, 
  Truck,
  Users,
  Building2,
  PackageCheck,
  Menu,
  X,
  UserCheck,
  Car
} from 'lucide-react';
import { UserProfile } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  user: UserProfile;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  onLogout: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, user, activeTab, setActiveTab, onLogout }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard, roles: ['ADMIN', 'CONFERENTE'] },
    { id: 'generate', label: 'Gerar Etiquetas', icon: PlusCircle, roles: ['ADMIN', 'CONFERENTE'] },
    { id: 'loading-manifest', label: 'Manifesto de Carga', icon: Truck, roles: ['ADMIN', 'CONFERENTE'] },
    { id: 'history', label: 'Histórico Geral', icon: History, roles: ['ADMIN', 'CONFERENTE'] },
    { id: 'checkers', label: 'Conferentes', icon: UserCheck, roles: ['ADMIN'] },
    { id: 'drivers', label: 'Motoristas', icon: Users, roles: ['ADMIN'] },
    { id: 'vehicles', label: 'Veículos', icon: Car, roles: ['ADMIN'] },
    { id: 'branches', label: 'Filiais', icon: Building2, roles: ['ADMIN'] },
  ];

  const handleTabChange = (id: string) => {
    setActiveTab(id);
    setIsMobileMenuOpen(false);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-inter">
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-slate-900/60 z-40 lg:hidden backdrop-blur-sm" onClick={() => setIsMobileMenuOpen(false)} />
      )}
      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-slate-300 flex flex-col no-print transition-transform duration-300 transform lg:relative lg:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-6 flex items-center justify-between border-b border-slate-800">
          <div className="flex items-center gap-3">
            <PackageCheck className="text-blue-500 w-8 h-8" />
            <span className="font-bold text-xl text-white tracking-tight">LogiLabel<span className="text-blue-500">Pro</span></span>
          </div>
          <button className="lg:hidden text-slate-400" onClick={() => setIsMobileMenuOpen(false)}><X size={24} /></button>
        </div>
        <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
          {menuItems.map((item) => {
            if (!item.roles.includes(user.role)) return null;
            const Icon = item.icon;
            const isActive = activeTab === item.id;
            return (
              <button key={item.id} onClick={() => handleTabChange(item.id)} className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${isActive ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-slate-800 hover:text-white'}`}>
                <Icon size={20} />
                <span className="font-medium text-sm">{item.label}</span>
              </button>
            );
          })}
        </nav>
        <div className="p-4 border-t border-slate-800 space-y-4">
          <div className="px-4 py-2 bg-slate-800/50 rounded-lg">
            <p className="text-[10px] text-slate-500 uppercase font-bold">Logado como</p>
            <p className="text-sm font-semibold text-white truncate">{user.name}</p>
          </div>
          <button onClick={onLogout} className="w-full flex items-center gap-3 px-4 py-3 text-slate-400 hover:text-red-400 hover:bg-red-500/10 rounded-lg transition-colors">
            <LogOut size={20} />
            <span className="font-medium text-sm">Sair</span>
          </button>
        </div>
      </aside>
      <main className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-8 no-print shrink-0">
          <div className="flex items-center gap-4">
            <button className="lg:hidden p-2 text-slate-600" onClick={() => setIsMobileMenuOpen(true)}><Menu size={24} /></button>
            <h1 className="text-lg font-bold text-slate-800">{menuItems.find(i => i.id === activeTab)?.label || 'Sistema'}</h1>
          </div>
          <div className="text-xs text-slate-500">{new Date().toLocaleDateString('pt-BR', { weekday: 'long', day: 'numeric', month: 'long' })}</div>
        </header>
        <div className="flex-1 overflow-y-auto p-8">
          {children}
        </div>
      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ManifestForm from './components/ManifestForm';
import LoadingManifestForm from './components/LoadingManifestForm';
import { 
  UserProfile, 
  Manifest, 
  LoadingManifest,
  Checker, 
  Driver,
  Vehicle,
  Branch, 
  DistributionCenter 
} from './types';
import { 
  INITIAL_CHECKERS, 
  INITIAL_BRANCHES, 
  INITIAL_CDS 
} from './services/mockData';
import { 
  Search, 
  RefreshCcw, 
  Printer, 
  Plus, 
  Trash2, 
  UserPlus, 
  MapPin, 
  Warehouse,
  Lock,
  X,
  Check,
  Truck,
  Car
} from 'lucide-react';
import { generateManifestPDF, generateLoadingManifestPDF } from './services/pdfGenerator';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('logi_user');
    return saved ? JSON.parse(saved) : null;
  });

  const [manifests, setManifests] = useState<Manifest[]>(() => {
    const saved = localStorage.getItem('logi_manifests');
    return saved ? JSON.parse(saved) : [];
  });

  const [loadingManifests, setLoadingManifests] = useState<LoadingManifest[]>(() => {
    const saved = localStorage.getItem('logi_loading_manifests');
    return saved ? JSON.parse(saved) : [];
  });

  const [checkers, setCheckers] = useState<Checker[]>(() => {
    const saved = localStorage.getItem('logi_checkers');
    return saved ? JSON.parse(saved) : INITIAL_CHECKERS;
  });

  const [drivers, setDrivers] = useState<Driver[]>(() => {
    const saved = localStorage.getItem('logi_drivers');
    return saved ? JSON.parse(saved) : [];
  });

  const [vehicles, setVehicles] = useState<Vehicle[]>(() => {
    const saved = localStorage.getItem('logi_vehicles');
    return saved ? JSON.parse(saved) : [];
  });

  const [branches, setBranches] = useState<Branch[]>(() => {
    const saved = localStorage.getItem('logi_branches');
    return saved ? JSON.parse(saved) : INITIAL_BRANCHES;
  });

  const [cds, setCds] = useState<DistributionCenter[]>(() => {
    const saved = localStorage.getItem('logi_cds');
    return saved ? JSON.parse(saved) : INITIAL_CDS;
  });

  // UI States
  const [loginForm, setLoginForm] = useState({ email: '', password: '' });
  const [loginError, setLoginError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [searchTerm, setSearchTerm] = useState('');

  const [showAddChecker, setShowAddChecker] = useState(false);
  const [showAddDriver, setShowAddDriver] = useState(false);
  const [showAddVehicle, setShowAddVehicle] = useState(false);
  const [showAddBranch, setShowAddBranch] = useState(false);
  const [showAddCD, setShowAddCD] = useState(false);

  const [newChecker, setNewChecker] = useState({ name: '', externalId: '' });
  const [newDriver, setNewDriver] = useState({ name: '', document: '', phone: '' });
