import React, { useState, useEffect, useRef } from 'react';
import { 
  Truck, 
  Scan, 
  Trash2, 
  AlertCircle, 
  CheckCircle2, 
  FileDown, 
  Eye,
  Loader2,
  X,
  ExternalLink,
  Download,
  Printer,
  Clock
} from 'lucide-react';
import { 
  Driver, 
  Vehicle, 
  Branch, 
  DistributionCenter, 
  LoadingManifest, 
  InvoiceItem 
} from '../types';
import { generateLoadingManifestPDF } from '../services/pdfGenerator';

interface LoadingManifestFormProps {
  drivers: Driver[];
  vehicles: Vehicle[];
  branches: Branch[];
  cds: DistributionCenter[];
  onSave: (m: LoadingManifest) => void;
  currentUser: { name: string; uid: string };
}

const LoadingManifestForm: React.FC<LoadingManifestFormProps> = ({ 
  drivers, 
  vehicles, 
  branches, 
  cds, 
  onSave,
  currentUser
}) => {
  const [formData, setFormData] = useState({
    manifestNumber: `MC-${Date.now().toString().substr(-6)}`,
    cdId: cds[0]?.id || '',
    branchId: '',
    driverId: '',
    vehicleId: '',
    sealNumber: '',
    deliveryDate: new Date().toISOString().split('T')[0],
    exitTime: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
  });

  const [invoices, setInvoices] = useState<InvoiceItem[]>([]);
  const [scannerInput, setScannerInput] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const scannerRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    return () => { if (previewUrl) URL.revokeObjectURL(previewUrl); };
  }, [previewUrl]);

  const activeDrivers = drivers.filter(d => d.status === 'ATIVO');
  const activeVehicles = vehicles.filter(v => v.status === 'ATIVO');
  const activeBranches = branches.filter(b => b.status === 'ATIVO');

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    const val = scannerInput.trim();
    if (val.length !== 44 || !/^\d+$/.test(val)) {
      setError("Chave de acesso inválida! Deve conter exatamente 44 dígitos numéricos.");
      setScannerInput('');
      return;
    }

    if (invoices.some(i => i.key === val)) {
      setError("Esta Nota Fiscal já foi bipada neste manifesto.");
      setScannerInput('');
      return;
    }

    // Extract NF number: positions 26 to 34 (9 digits)
    const nfNumber = val.substring(25, 34);

    setInvoices([{ key: val, number: nfNumber }, ...invoices]);
    setScannerInput('');
    scannerRef.current?.focus();
  };

  const removeInvoice = (key: string) => {
    setInvoices(invoices.filter(i => i.key !== key));
  };

  const validate = () => {
    if (!formData.branchId) return "Selecione a filial de destino";
    if (!formData.driverId) return "Selecione o motorista";
    if (!formData.vehicleId) return "Selecione o veículo";
    if (!formData.exitTime) return "Informe o horário de saída";
    if (invoices.length === 0) return "Bipe pelo menos uma Nota Fiscal";
    return null;
  };

  const constructManifest = (): LoadingManifest => {
    const cd = cds.find(c => c.id === formData.cdId);
    const branch = branches.find(b => b.id === formData.branchId);
    const driver = drivers.find(d => d.id === formData.driverId);
    const vehicle = vehicles.find(v => v.id === formData.vehicleId);

    return {
      id: `lm_${Date.now()}`,
      ...formData,
      invoices,
      createdAt: new Date().toISOString(),
      createdBy: currentUser.name,
      cdName: cd?.name || '',
      branchName: branch?.name || '',
      driverName: driver?.name || '',
      vehiclePlate: vehicle?.plate || ''
    };
  };

  const handlePreview = async () => {
    const err = validate();
    if (err) { setError(err); return; }
    setError(null);
    setIsGenerating(true);
    try {
      if (previewUrl) URL.revokeObjectURL(previewUrl);
      const m = constructManifest();
      const url = await generateLoadingManifestPDF(m, true);
      setPreviewUrl(url);
    } catch (e) { 
      setError("Erro ao gerar PDF."); 
      console.error(e);
    }
    finally { setIsGenerating(false); }
  };

  const handleSave = async () => {
    const err = validate();
    if (err) { setError(err); return; }
    setIsGenerating(true);
    try {
      const m = constructManifest();
      await generateLoadingManifestPDF(m, false);
      onSave(m);
      // Reset
      setInvoices([]);
      setFormData({ 
        ...formData, 
        manifestNumber: `MC-${Date.now().toString().substr(-6)}`, 
        sealNumber: '',
        exitTime: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
      });
    } catch (e) { setError("Erro ao salvar manifesto."); }
    finally { setIsGenerating(false); }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6">
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 bg-slate-800 text-white flex items-center gap-3">
          <Truck />
          <h2 className="font-bold">Gerar Manifesto de Carga (Embarque)</h2>
        </div>

        <div className="p-6 grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Form Side */}
          <div className="space-y-4 lg:col-span-1 border-r border-slate-100 pr-0 lg:pr-8">
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Unidade de Origem</label>
              <select 
                className="w-full p-2 border rounded bg-slate-50"
                value={formData.cdId}
                onChange={e => setFormData({...formData, cdId: e.target.value})}
              >
                {cds.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Filial de Destino *</label>
              <select 
                className="w-full p-2 border rounded"
                value={formData.branchId}
                onChange={e => setFormData({...formData, branchId: e.target.value})}
              >
                <option value="">Selecione...</option>
                {activeBranches.map(b => <option key={b.id} value={b.id}>{b.name} ({b.code})</option>)}
              </select>
            </div>

            <div className="grid grid-cols-2 gap-4">
               <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Motorista *</label>
                <select 
                  className="w-full p-2 border rounded"
                  value={formData.driverId}
                  onChange={e => setFormData({...formData, driverId: e.target.value})}
                >
                  <option value="">Selecione...</option>
                  {activeDrivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Veículo *</label>
                <select 
                  className="w-full p-2 border rounded"
                  value={formData.vehicleId}
                  onChange={e => setFormData({...formData, vehicleId: e.target.value})}
                >
                  <option value="">Selecione...</option>
                  {activeVehicles.map(v => <option key={v.id} value={v.id}>{v.plate} - {v.model}</option>)}
                </select>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Nº Lacre</label>
                <input 
                  type="text" 
                  className="w-full p-2 border rounded"
                  value={formData.sealNumber}
                  onChange={e => setFormData({...formData, sealNumber: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Data Entrega *</label>
                <input 
                  type="date" 
                  className="w-full p-2 border rounded"
                  value={formData.deliveryDate}
                  onChange={e => setFormData({...formData, deliveryDate: e.target.value})}
                />
              </div>
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Horário de Saída *</label>
              <div className="relative">
                <Clock className="absolute left-3 top-2.5 text-slate-400" size={16} />
                <input 
                  type="time" 
                  className="w-full pl-10 p-2 border rounded focus:ring-2 focus:ring-blue-500 outline-none"
                  value={formData.exitTime}
                  onChange={e => setFormData({...formData, exitTime: e.target.value})}
                />
              </div>
            </div>

            <div className="pt-4 space-y-3">
              <button 
                onClick={handlePreview}
                disabled={isGenerating}
                className="w-full py-3 bg-slate-100 text-slate-700 font-bold rounded-lg hover:bg-slate-200 flex items-center justify-center gap-2"
              >
                {isGenerating ? <Loader2 className="animate-spin" size={18} /> : <Eye size={18} />}
                Visualizar PDF
              </button>
              <button 
                onClick={handleSave}
                disabled={isGenerating}
                className="w-full py-3 bg-blue-600 text-white font-bold rounded-lg hover:bg-blue-700 shadow-lg shadow-blue-200 flex items-center justify-center gap-2"
              >
                {isGenerating ? <Loader2 className="animate-spin" size={18} /> : <FileDown size={18} />}
                Gerar & Salvar
              </button>
            </div>
            {error && (
              <div className="p-3 bg-red-50 text-red-600 text-[10px] rounded border border-red-100 flex items-center gap-2">
                <AlertCircle size={14} /> {error}
              </div>
            )}
          </div>

          {/* Scanner Side */}
          <div className="lg:col-span-2 space-y-6">
            <form onSubmit={handleScan} className="bg-blue-50 p-6 rounded-xl border border-blue-100">
              <div className="flex items-center gap-3 mb-4">
                <Scan className="text-blue-600" />
                <h3 className="font-bold text-blue-900 uppercase text-sm tracking-widest">Bipagem de Notas Fiscais</h3>
              </div>
              <div className="relative">
                <input 
                  ref={scannerRef}
                  type="text"
                  placeholder="Bipe a Chave de Acesso (44 dígitos)..."
                  className="w-full p-4 pr-16 border-2 border-blue-200 rounded-xl focus:ring-4 focus:ring-blue-100 outline-none text-lg font-mono tracking-tighter"
                  value={scannerInput}
                  onChange={e => setScannerInput(e.target.value)}
                  autoFocus
                />
                <button 
                  type="submit"
                  className="absolute right-2 top-2 bottom-2 px-4 bg-blue-600 text-white rounded-lg font-bold"
                >
                  OK
                </button>
              </div>
            </form>

            <div className="bg-white border rounded-xl overflow-hidden shadow-inner">
              <div className="p-3 bg-slate-50 border-b flex justify-between items-center">
                <span className="text-xs font-bold text-slate-500 uppercase">Itens Bipados ({invoices.length})</span>
                {invoices.length > 0 && (
                  <button 
                    onClick={() => setInvoices([])}
                    className="text-[10px] font-bold text-red-500 hover:underline"
                  >
                    Limpar Tudo
                  </button>
                )}
              </div>
              <div className="max-h-[400px] overflow-y-auto">
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50/50 text-[10px] font-bold text-slate-400 uppercase">
                    <tr>
                      <th className="px-4 py-2">NF</th>
                      <th className="px-4 py-2">Chave de Acesso</th>
                      <th className="px-4 py-2 text-right">Ação</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y">
                    {invoices.map((inv) => (
                      <tr key={inv.key} className="hover:bg-slate-50 group">
                        <td className="px-4 py-3 font-bold text-blue-600">{inv.number}</td>
                        <td className="px-4 py-3 text-slate-500 font-mono text-[11px] truncate max-w-[300px]">{inv.key}</td>
                        <td className="px-4 py-3 text-right">
                          <button 
                            onClick={() => removeInvoice(inv.key)}
                            className="p-1.5 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded"
                          >
                            <Trash2 size={16} />
                          </button>
                        </td>
                      </tr>
                    ))}
                    {invoices.length === 0 && (
                      <tr>
                        <td colSpan={3} className="px-4 py-20 text-center text-slate-400 italic">
                          Aguardando bipagem das notas...
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Preview Modal */}
      {previewUrl && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-5xl h-[90vh] rounded-2xl flex flex-col overflow-hidden shadow-2xl">
            <div className="p-4 border-b flex justify-between items-center bg-slate-50">
              <h3 className="font-bold flex items-center gap-2 text-slate-800">
                <Eye size={18} className="text-blue-600" /> 
                Visualização do Manifesto de Carga
              </h3>
              <button onClick={() => setPreviewUrl(null)} className="p-2 hover:bg-red-100 hover:text-red-600 rounded-full transition-colors"><X /></button>
            </div>

            <div className="flex-1 bg-slate-200 p-4 relative flex items-center justify-center">
              <div className="w-full h-full bg-white shadow-inner rounded overflow-hidden">
                <object 
                  data={previewUrl} 
                  type="application/pdf" 
                  className="w-full h-full"
                >
                  <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-4">
                    <Printer size={48} className="text-slate-400" />
                    <div>
                      <h4 className="font-bold text-slate-700">O PDF está pronto</h4>
                      <p className="text-sm text-slate-500">Seu navegador não suporta a visualização direta. Clique abaixo para abrir.</p>
                    </div>
                    <a 
                      href={previewUrl} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="inline-flex items-center gap-2 px-6 py-2 bg-blue-600 text-white rounded-lg font-bold shadow-lg"
                    >
                      <ExternalLink size={18} /> Abrir em Nova Aba
                    </a>
                  </div>
                </object>
              </div>
            </div>

            <div className="p-4 flex flex-col sm:flex-row justify-end gap-3 border-t bg-white">
              <button 
                onClick={() => setPreviewUrl(null)} 
                className="px-6 py-2 bg-slate-200 text-slate-700 font-bold rounded-lg hover:bg-slate-300 transition-colors"
              >
                Fechar
              </button>
              <button 
                onClick={() => {
                   const link = document.createElement('a');
                   link.href = previewUrl;
                   link.download = `Manifesto_Carga_${formData.manifestNumber}.pdf`;
                   link.click();
                }}
                className="px-6 py-2 bg-blue-600 text-white font-bold rounded-lg flex items-center justify-center gap-2 shadow-lg shadow-blue-200 hover:bg-blue-700 transition-all"
              >
                <Download size={18} /> Baixar PDF
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
