const Layout: React.FC<LayoutProps> = ({ children, user, activeTab, setActiveTab, onLogout }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard, roles: ['ADMIN', 'CONFERENTE'] },
    { id: 'generate', label: 'Gerar Etiquetas', icon: PlusCircle, roles: ['ADMIN', 'CONFERENTE'] },
    { id: 'loading-manifest', label: 'Manifesto de Carga', icon: Truck, roles: ['ADMIN', 'CONFERENTE'] },
