  </div>
);

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('logi_user');
    return saved ? JSON.parse(saved) : null;
  });

  const [allUsers, setAllUsers] = useState<UserProfile[]>(() => {
    const saved = localStorage.getItem('logi_all_users');
    const defaultAdmin: UserProfile = { 
      uid: 'u_diego', 
      email: 'diego.silva', 
      name: 'Diego Silva', 
      role: 'ADMIN', 
      password: '05171888302' 
    };
    return saved ? JSON.parse(saved) : [defaultAdmin];
  });

  const [manifests, setManifests] = useState<Manifest[]>(() => {
    const saved = localStorage.getItem('logi_manifests');
    return saved ? JSON.parse(saved) : [];
  });

  const [loadingManifests, setLoadingManifests] = useState<LoadingManifest[]>(() => {
    const saved = localStorage.getItem('logi_loading_manifests');
    return saved ? JSON.parse(saved) : [];
  });

  const [checkers, setCheckers] = useState<Checker[]>(() => {
    const saved = localStorage.getItem('logi_checkers');
    return saved ? JSON.parse(saved) : INITIAL_CHECKERS;
  });

  const [drivers, setDrivers] = useState<Driver[]>(() => {
    const saved = localStorage.getItem('logi_drivers');
    return saved ? JSON.parse(saved) : [];
  });

  const [vehicles, setVehicles] = useState<Vehicle[]>(() => {
    const saved = localStorage.getItem('logi_vehicles');
    return saved ? JSON.parse(saved) : [];
  });

  const [branches, setBranches] = useState<Branch[]>(() => {
    const saved = localStorage.getItem('logi_branches');
    return saved ? JSON.parse(saved) : INITIAL_BRANCHES;
  });

  const [cds, setCds] = useState<DistributionCenter[]>(() => {
    const saved = localStorage.getItem('logi_cds');
    return saved ? JSON.parse(saved) : INITIAL_CDS;
  });

  const [loginForm, setLoginForm] = useState({ email: '', password: '' });
  const [loginError, setLoginError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [searchTerm, setSearchTerm] = useState('');
  const [showAddUser, setShowAddUser] = useState(false);
  const [showAddChecker, setShowAddChecker] = useState(false);
  const [showAddDriver, setShowAddDriver] = useState(false);
  const [showAddVehicle, setShowAddVehicle] = useState(false);
  const [showAddBranch, setShowAddBranch] = useState(false);

  const [newUser, setNewUser] = useState({ name: '', email: '', password: '', role: 'CONFERENTE' as UserProfile['role'] });
  const [newChecker, setNewChecker] = useState({ name: '', externalId: '' });
  const [newDriver, setNewDriver] = useState({ name: '', document: '', phone: '' });
  const [newVehicle, setNewVehicle] = useState({ plate: '', model: '', type: 'TRUCK' });
  const [newBranch, setNewBranch] = useState({ name: '', code: '', city: '', state: '' });

  useEffect(() => { localStorage.setItem('logi_all_users', JSON.stringify(allUsers)); }, [allUsers]);
  useEffect(() => { localStorage.setItem('logi_manifests', JSON.stringify(manifests)); }, [manifests]);
  useEffect(() => { localStorage.setItem('logi_loading_manifests', JSON.stringify(loadingManifests)); }, [loadingManifests]);
  useEffect(() => { localStorage.setItem('logi_checkers', JSON.stringify(checkers)); }, [checkers]);
  useEffect(() => { localStorage.setItem('logi_drivers', JSON.stringify(drivers)); }, [drivers]);
  useEffect(() => { localStorage.setItem('logi_vehicles', JSON.stringify(vehicles)); }, [vehicles]);
  useEffect(() => { localStorage.setItem('logi_branches', JSON.stringify(branches)); }, [branches]);
  useEffect(() => { localStorage.setItem('logi_cds', JSON.stringify(cds)); }, [cds]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError(null);
    const emailInput = loginForm.email.toLowerCase();
    const passwordInput = loginForm.password;
    const foundUser = allUsers.find(u => (u.email.toLowerCase() === emailInput || u.uid === emailInput) && u.password === passwordInput);
    if (foundUser) {
      setUser(foundUser);
      localStorage.setItem('logi_user', JSON.stringify(foundUser));
    } else {
      setLoginError('Credenciais inválidas.');
    }
  };

  const handleLogout = () => { setUser(null); localStorage.removeItem('logi_user'); };

  const addUser = () => {
    if (newUser.name && newUser.email && newUser.password) {
      const u: UserProfile = { uid: `u_${Date.now()}`, name: newUser.name, email: newUser.email, password: newUser.password, role: newUser.role };
      setAllUsers([...allUsers, u]);
      setNewUser({ name: '', email: '', password: '', role: 'CONFERENTE' });
      setShowAddUser(false);
    }
  };

  const addChecker = () => {
    if (newChecker.name) {
      setCheckers([...checkers, { id: `c_${Date.now()}`, ...newChecker, status: 'ATIVO' }]);
      setNewChecker({ name: '', externalId: '' });
      setShowAddChecker(false);
    }
  };

  const addDriver = () => {
    if (newDriver.name) {
      setDrivers([...drivers, { id: `d_${Date.now()}`, ...newDriver, status: 'ATIVO' }]);
      setNewDriver({ name: '', document: '', phone: '' });
      setShowAddDriver(false);
    }
  };

  const addVehicle = () => {
    if (newVehicle.plate) {
      setVehicles([...vehicles, { id: `v_${Date.now()}`, ...newVehicle, status: 'ATIVO' }]);
      setNewVehicle({ plate: '', model: '', type: 'TRUCK' });
      setShowAddVehicle(false);
    }
  };

  const addBranch = () => {
    if (newBranch.name && newBranch.code) {
      setBranches([...branches, { id: `b_${Date.now()}`, ...newBranch, status: 'ATIVO' }]);
      setNewBranch({ name: '', code: '', city: '', state: '' });
      setShowAddBranch(false);
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-100 p-4 font-inter">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl overflow-hidden border border-slate-200">
          <div className="bg-slate-900 p-10 text-center text-white relative">
             <div className="absolute top-0 left-0 w-full h-1 bg-orange-600"></div>
             <LogoNormatel size={64} className="mx-auto mb-4" />
             <h1 className="text-2xl font-black tracking-tighter uppercase italic">Logística <span className="text-orange-600">Normatel</span></h1>
             <p className="text-slate-400 text-xs mt-1 font-medium tracking-widest uppercase">Warehouse Control Center</p>
          </div>
          <form onSubmit={handleLogin} className="p-8 space-y-5">
             {loginError && (
               <div className="p-3 bg-red-50 text-red-600 text-xs rounded-xl border border-red-100 flex items-center gap-2">
                 <Lock size={14} /> {loginError}
               </div>
             )}
             <div className="space-y-1">
               <label className="text-[10px] font-bold text-slate-500 uppercase ml-1">Usuário</label>
               <input className="w-full p-4 bg-slate-50 border-0 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none transition-all font-medium" type="text" placeholder="ID de Usuário" value={loginForm.email} onChange={e => setLoginForm({...loginForm, email: e.target.value})} required />
             </div>
             <div className="space-y-1">
               <label className="text-[10px] font-bold text-slate-500 uppercase ml-1">Senha</label>
               <input className="w-full p-4 bg-slate-50 border-0 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none transition-all" type="password" placeholder="••••••••" value={loginForm.password} onChange={e => setLoginForm({...loginForm, password: e.target.value})} required />
             </div>
             <button type="submit" className="w-full py-4 bg-orange-600 text-white font-black rounded-2xl shadow-xl shadow-orange-200 transition-all active:scale-95 hover:bg-orange-700 uppercase tracking-widest text-sm">Entrar no Sistema</button>
          </form>
          <div className="p-6 bg-slate-50 text-center border-t border-slate-100">
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">© 2024 NORMATEL LOGISTICA - V1.5.0</p>
          </div>
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard manifests={manifests} />;
      case 'generate': return <ManifestForm checkers={checkers} branches={branches} cds={cds} onSave={m => setManifests([m, ...manifests])} currentUser={user} />;
      case 'loading-manifest': return <LoadingManifestForm drivers={drivers} vehicles={vehicles} branches={branches} cds={cds} onSave={m => setLoadingManifests([m, ...loadingManifests])} currentUser={user} />;
      case 'users':
        return (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-bold flex items-center gap-2 text-slate-800">
                <UserCog className="text-orange-600" /> Gerenciamento de Usuários
              </h3>
              <button onClick={() => setShowAddUser(true)} className="px-4 py-2 bg-orange-600 text-white rounded-xl flex items-center gap-2 font-bold shadow-lg shadow-orange-100 hover:bg-orange-700">
                <UserPlus size={18}/> Novo Usuário
              </button>
            </div>
            {showAddUser && (
              <div className="p-6 bg-white border rounded-2xl shadow-sm space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                  <input placeholder="Nome Completo" className="p-3 border rounded-xl" value={newUser.name} onChange={e => setNewUser({...newUser, name: e.target.value})} />
                  <input placeholder="Usuário" className="p-3 border rounded-xl" value={newUser.email} onChange={e => setNewUser({...newUser, email: e.target.value})} />
                  <input type="password" placeholder="Senha" className="p-3 border rounded-xl" value={newUser.password} onChange={e => setNewUser({...newUser, password: e.target.value})} />
                  <select className="p-3 border rounded-xl" value={newUser.role} onChange={e => setNewUser({...newUser, role: e.target.value as any})}>
                    <option value="CONFERENTE">CONFERENTE</option>
                    <option value="ADMINISTRATIVO">ADMINISTRATIVO</option>
                    <option value="ADMIN">ADMINISTRADOR</option>
                  </select>
                </div>
                <div className="flex justify-end gap-2">
                  <button onClick={() => setShowAddUser(false)} className="px-4 py-2 bg-slate-100 rounded-xl font-bold">Cancelar</button>
                  <button onClick={addUser} className="px-6 py-2 bg-orange-600 text-white rounded-xl font-bold">Salvar</button>
                </div>
              </div>
            )}
            <div className="bg-white rounded-2xl border overflow-hidden shadow-sm">
               <table className="w-full text-left">
                  <thead className="bg-slate-50 text-[10px] font-bold uppercase text-slate-500 border-b">
                    <tr><th className="p-4">Nome</th><th className="p-4">Usuário</th><th className="p-4">Perfil</th><th className="p-4 text-center">Ação</th></tr>
                  </thead>
                  <tbody className="divide-y">{allUsers.map(u => (
                      <tr key={u.uid} className="hover:bg-slate-50 transition-colors">
                        <td className="p-4 flex items-center gap-3"><div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-400"><User size={16} /></div><span className="font-bold text-slate-700">{u.name}</span></td>
                        <td className="p-4 text-slate-500 font-mono text-sm">{u.email}</td>
                        <td className="p-4"><span className={`px-2 py-1 rounded-lg text-[10px] font-black tracking-wider ${u.role === 'ADMIN' ? 'bg-orange-100 text-orange-700' : 'bg-slate-100 text-slate-600'}`}>{u.role}</span></td>
                        <td className="p-4 text-center">{u.uid !== user.uid && u.uid !== 'u_diego' && (<button onClick={() => setAllUsers(allUsers.filter(x => x.uid !== u.uid))} className="p-2 text-red-400 hover:text-red-600 transition-colors"><Trash2 size={18}/></button>)}</td>
                      </tr>
                    ))}</tbody>
               </table>
            </div>
          </div>
        );
      case 'checkers':
        return (
          <div className="space-y-4">
             <div className="flex justify-between items-center">
              <h3 className="text-lg font-bold">Conferentes</h3>
              <button onClick={() => setShowAddChecker(true)} className="px-4 py-2 bg-orange-600 text-white rounded-xl flex items-center gap-2 font-bold"><UserPlus size={18}/> Novo</button>
            </div>
            {showAddChecker && (
              <div className="p-4 bg-white border rounded-2xl flex gap-3">
                <input placeholder="Nome" className="flex-1 p-3 border rounded-xl" value={newChecker.name} onChange={e => setNewChecker({...newChecker, name: e.target.value})} />
                <input placeholder="ID Crachá" className="w-32 p-3 border rounded-xl" value={newChecker.externalId} onChange={e => setNewChecker({...newChecker, externalId: e.target.value})} />
                <button onClick={addChecker} className="bg-orange-600 text-white px-6 rounded-xl font-bold">Salvar</button>
              </div>
            )}
            <div className="bg-white rounded-2xl border overflow-hidden shadow-sm">
               <table className="w-full text-left">
                  <thead className="bg-slate-50 text-[10px] font-bold uppercase text-slate-500 border-b"><tr><th className="p-4">Nome</th><th className="p-4">ID</th><th className="p-4 text-center">Ação</th></tr></thead>
                  <tbody className="divide-y">{checkers.map(c => <tr key={c.id} className="hover:bg-slate-50"><td className="p-4 font-bold">{c.name}</td><td className="p-4 text-slate-500 font-mono">{c.externalId}</td><td className="p-4 text-center"><button onClick={() => setCheckers(checkers.filter(x => x.id !== c.id))} className="text-red-400"><Trash2 size={18}/></button></td></tr>)}</tbody>
               </table>
            </div>
          </div>
        );
      case 'history':
        return (
          <div className="space-y-6">
             <div className="relative">
                <Search className="absolute left-4 top-3.5 text-slate-400" size={18} />
                <input className="w-full pl-12 pr-4 py-4 bg-white border-0 rounded-2xl shadow-sm focus:ring-2 focus:ring-orange-500 outline-none" placeholder="Pesquisar por número do manifesto ou carga..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
             </div>
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <div className="bg-white rounded-2xl border shadow-sm overflow-hidden">
                  <div className="p-4 bg-slate-50 border-b font-black text-[10px] uppercase text-slate-400 tracking-widest">Etiquetas de Conferência</div>
                  <table className="w-full text-left text-sm">
                    <thead><tr className="bg-slate-50/50 border-b"><th className="p-3">Nº</th><th className="p-3">Destino</th><th className="p-3 text-center">Ação</th></tr></thead>
                    <tbody className="divide-y">{manifests.filter(m => m.manifestNumber.includes(searchTerm)).map(m => (
                      <tr key={m.id} className="hover:bg-slate-50">
                        <td className="p-3 font-bold text-orange-600">{m.manifestNumber}</td><td className="p-3 font-medium">{m.branchName}</td>
                        <td className="p-3 text-center"><button onClick={() => generateManifestPDF(m)} className="p-2 text-slate-400 hover:text-orange-600 transition-colors"><Printer size={16}/></button></td>
                      </tr>
                    ))}</tbody>
                  </table>
                </div>
                <div className="bg-white rounded-2xl border shadow-sm overflow-hidden">
                  <div className="p-4 bg-slate-800 text-white font-black text-[10px] uppercase tracking-widest">Manifestos de Carga</div>
                  <table className="w-full text-left text-sm">
                    <thead><tr className="bg-slate-50/50 border-b"><th className="p-3">Carga</th><th className="p-3">Veículo</th><th className="p-3 text-center">Ação</th></tr></thead>
                    <tbody className="divide-y">{loadingManifests.filter(m => m.manifestNumber.includes(searchTerm)).map(m => (
                      <tr key={m.id} className="hover:bg-slate-50">
                        <td className="p-3 font-bold text-slate-800">{m.manifestNumber}</td><td className="p-3 text-slate-500 font-mono text-xs">{m.vehiclePlate}</td>
                        <td className="p-3 text-center"><button onClick={() => generateLoadingManifestPDF(m)} className="p-2 text-slate-400 hover:text-orange-600 transition-colors"><Printer size={16}/></button></td>
                      </tr>
                    ))}</tbody>
                  </table>
                </div>
             </div>
          </div>
        );
      default: return <Dashboard manifests={manifests} />;
    }
  };

  return (
    <Layout user={user} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { 
  LayoutDashboard, 
  PlusCircle, 
  History, 
  LogOut, 
  Truck,
  Users,
  Building2,
  Menu,
  X,
  UserCheck,
  Car,
  UserCog
} from 'lucide-react';
import { UserProfile } from '../types';

const LogoSmall = () => (
  <svg viewBox="0 0 100 100" className="w-8 h-8">
    <path d="M20 80 L50 40 L80 40 L50 80 Z" fill="#ea580c" />
    <path d="M20 20 L50 60 L80 60 L50 20 Z" fill="#ea580c" />
  </svg>
);

interface LayoutProps {
  children: React.ReactNode;
  user: UserProfile;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  onLogout: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, user, activeTab, setActiveTab, onLogout }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard, roles: ['ADMIN', 'CONFERENTE', 'ADMINISTRATIVO'] },
    { id: 'generate', label: 'Conferência', icon: PlusCircle, roles: ['ADMIN', 'CONFERENTE', 'ADMINISTRATIVO'] },
    { id: 'loading-manifest', label: 'Carga/Embarque', icon: Truck, roles: ['ADMIN', 'CONFERENTE', 'ADMINISTRATIVO'] },
    { id: 'history', label: 'Histórico', icon: History, roles: ['ADMIN', 'CONFERENTE', 'ADMINISTRATIVO'] },
    { id: 'users', label: 'Usuários', icon: UserCog, roles: ['ADMIN'] },
    { id: 'checkers', label: 'Conferentes', icon: UserCheck, roles: ['ADMIN', 'ADMINISTRATIVO'] },
    { id: 'drivers', label: 'Motoristas', icon: Users, roles: ['ADMIN', 'ADMINISTRATIVO'] },
    { id: 'vehicles', label: 'Veículos', icon: Car, roles: ['ADMIN', 'ADMINISTRATIVO'] },
    { id: 'branches', label: 'Filiais', icon: Building2, roles: ['ADMIN', 'ADMINISTRATIVO'] },
  ];

  const handleTabChange = (id: string) => {
    setActiveTab(id);
    setIsMobileMenuOpen(false);
  };

  return (
    <div className="flex h-screen bg-slate-100 overflow-hidden font-inter">
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-slate-900/60 z-40 lg:hidden backdrop-blur-sm" onClick={() => setIsMobileMenuOpen(false)} />
      )}
      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-slate-300 flex flex-col no-print transition-transform duration-300 transform lg:relative lg:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-6 flex items-center gap-3 border-b border-slate-800">
          <LogoSmall />
          <div className="flex flex-col">
            <span className="font-black text-lg text-white leading-none uppercase italic">Normatel</span>
            <span className="text-[8px] text-orange-500 font-bold uppercase tracking-widest">Logística & CD</span>
          </div>
        </div>
        <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
          {menuItems.map((item) => {
            if (!item.roles.includes(user.role)) return null;
            const Icon = item.icon;
            const isActive = activeTab === item.id;
            return (
              <button key={item.id} onClick={() => handleTabChange(item.id)} className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl transition-all ${isActive ? 'bg-orange-600 text-white shadow-lg shadow-orange-900/20' : 'hover:bg-slate-800 hover:text-white'}`}>
                <Icon size={18} className={isActive ? 'text-white' : 'text-slate-500'} />
                <span className="font-bold text-xs uppercase tracking-wider">{item.label}</span>
              </button>
            );
          })}
        </nav>
        <div className="p-4 border-t border-slate-800 space-y-4">
          <div className="px-4 py-3 bg-slate-800/50 rounded-2xl border border-slate-700/50">
            <p className="text-[8px] text-orange-500 uppercase font-black tracking-widest mb-1">Operador</p>
            <p className="text-xs font-bold text-white truncate">{user.name}</p>
            <p className="text-[10px] text-slate-500 font-medium">{user.role}</p>
          </div>
          <button onClick={onLogout} className="w-full flex items-center gap-3 px-4 py-3 text-slate-400 hover:text-red-400 hover:bg-red-500/10 rounded-2xl transition-colors">
            <LogOut size={18} />
            <span className="font-bold text-xs uppercase">Sair</span>
          </button>
        </div>
      </aside>
      <main className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-8 no-print shrink-0 shadow-sm z-10">
          <div className="flex items-center gap-4">
            <button className="lg:hidden p-2 text-slate-600" onClick={() => setIsMobileMenuOpen(true)}><Menu size={24} /></button>
            <h1 className="text-sm font-black text-slate-800 uppercase tracking-widest">{menuItems.find(i => i.id === activeTab)?.label || 'Sistema'}</h1>
          </div>
          <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{new Date().toLocaleDateString('pt-BR', { weekday: 'long', day: 'numeric', month: 'long' })}</div>
        </header>
        <div className="flex-1 overflow-y-auto p-8 bg-slate-50/50">
          {children}
        </div>
      </main>
    </div>
  );
};

export default Layout;

import React from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { FileText, Layers, TrendingUp, Calendar } from 'lucide-react';
import { Manifest } from '../types';

interface DashboardProps {
  manifests: Manifest[];
}

const Dashboard: React.FC<DashboardProps> = ({ manifests }) => {
  const today = new Date().toISOString().split('T')[0];
  const manifestsToday = manifests.filter(m => m.createdAt.startsWith(today));
  const palletsToday = manifestsToday.reduce((acc, m) => acc + m.palletsCount, 0);

  const dailyData = Array.from({ length: 7 }).map((_, i) => {
    const d = new Date();
    d.setDate(d.getDate() - (6 - i));
    const dateStr = d.toISOString().split('T')[0];
    const count = manifests.filter(m => m.createdAt.startsWith(dateStr)).length;
    return {
      name: d.toLocaleDateString('pt-BR', { weekday: 'short' }),
      date: dateStr,
      count
    };
  });

  const stats = [
    { label: 'CONFERÊNCIAS HOJE', value: manifestsToday.length, icon: FileText, color: 'bg-orange-600' },
    { label: 'PALETES EXPEDIDOS', value: palletsToday, icon: Layers, color: 'bg-slate-800' },
    { label: 'TOTAL ACUMULADO', value: manifests.length, icon: TrendingUp, color: 'bg-orange-500' },
    { label: 'MÉDIA SEMANAL', value: dailyData.reduce((a, b) => a + b.count, 0), icon: Calendar, color: 'bg-slate-700' },
  ];

  return (
    <div className="space-y-8">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, idx) => {
          const Icon = stat.icon;
          return (
            <div key={idx} className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex items-center gap-5 transition-transform hover:scale-[1.02]">
              <div className={`${stat.color} p-4 rounded-2xl text-white shadow-xl shadow-slate-200`}>
                <Icon size={24} />
              </div>
              <div>
                <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{stat.label}</p>
                <h3 className="text-3xl font-black text-slate-800 tracking-tighter">{stat.value}</h3>
              </div>
            </div>
          );
        })}
      </div>

      <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
        <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-8">Fluxo de Manifestos (Últimos 7 Dias)</h3>
        <div className="h-[300px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={dailyData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fill: '#94a3b8', fontSize: 10, fontWeight: 700 }} dy={10} />
              <YAxis axisLine={false} tickLine={false} tick={{ fill: '#94a3b8', fontSize: 10, fontWeight: 700 }} />
              <Tooltip cursor={{ fill: '#f8fafc' }} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', fontSize: '12px', fontWeight: 700 }} />
              <Bar dataKey="count" radius={[6, 6, 0, 0]} barSize={32}>
                {dailyData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={index === 6 ? '#ea580c' : '#334155'} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-6 border-b border-slate-100">
          <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Atividades Recentes</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-400 text-[10px] uppercase font-black tracking-widest border-b">
              <tr><th className="px-6 py-4">Manifesto</th><th className="px-6 py-4">Destino</th><th className="px-6 py-4">Paletes</th><th className="px-6 py-4">Status</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-100 text-sm">
              {manifests.slice(0, 5).map((m) => (
                <tr key={m.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 font-black text-orange-600">{m.manifestNumber}</td>
                  <td className="px-6 py-4 text-slate-700 font-bold">{m.branchName}</td>
                  <td className="px-6 py-4 text-slate-500">{m.palletsCount} un</td>
                  <td className="px-6 py-4">
                    <span className="px-2 py-1 bg-slate-100 text-slate-500 rounded-lg text-[10px] font-black uppercase tracking-tighter">Confirmado</span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { 
  FileDown, 
  Eye, 
  AlertCircle,
  X,
  Loader2,
  CheckCircle2,
  ExternalLink,
  Download,
  Printer
} from 'lucide-react';
import { 
  Checker, 
  Branch, 
  DistributionCenter, 
  Manifest 
} from '../types';
import { generateManifestPDF } from '../services/pdfGenerator';

interface ManifestFormProps {
  checkers: Checker[];
  branches: Branch[];
  cds: DistributionCenter[];
  onSave: (manifest: Manifest) => void;
  currentUser: { name: string; uid: string };
}

const ManifestForm: React.FC<ManifestFormProps> = ({ 
  checkers, 
  branches, 
  cds, 
  onSave,
  currentUser
}) => {
  const [formData, setFormData] = useState({
    manifestNumber: '',
    orders: '',
    conferenceDate: new Date().toISOString().split('T')[0],
    cdId: cds[0]?.id || '',
    branchId: '',
    checkerId: '',
    palletsCount: 1
  });

  const [isPreviewing, setIsPreviewing] = useState(false);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    return () => { if (previewUrl) URL.revokeObjectURL(previewUrl); };
  }, [previewUrl]);

  const activeCheckers = checkers.filter(c => c.status === 'ATIVO');
  const activeBranches = branches.filter(b => b.status === 'ATIVO');

  const validate = () => {
    if (!formData.manifestNumber) return "Nº Manifesto obrigatório";
    if (!formData.orders) return "Lista de pedidos obrigatória";
    if (!formData.branchId) return "Filial obrigatória";
    if (!formData.checkerId) return "Conferente obrigatório";
    return null;
  };

  const constructManifest = (): Manifest => {
    const cd = cds.find(c => c.id === formData.cdId);
    const branch = branches.find(b => b.id === formData.branchId);
    const checker = checkers.find(c => c.id === formData.checkerId);
    return {
      id: Math.random().toString(36).substr(2, 9),
      ...formData,
      createdAt: new Date().toISOString(),
      createdBy: currentUser.name,
      cdName: cd?.name || '',
      branchName: branch?.name || '',
      checkerName: checker?.name || ''
    };
  };

  const handlePreview = async () => {
    const err = validate();
    if (err) { setError(err); return; }
    setError(null);
    setIsGenerating(true);
    try {
      if (previewUrl) URL.revokeObjectURL(previewUrl);
      const manifest = constructManifest();
      const url = await generateManifestPDF(manifest, true);
      setPreviewUrl(url);
      setIsPreviewing(true);
    } catch (e) { setError("Erro ao gerar PDF."); }
    finally { setIsGenerating(false); }
  };

  const handleDownload = async () => {
    const err = validate();
    if (err) { setError(err); return; }
    setError(null);
    setIsGenerating(true);
    try {
      const manifest = constructManifest();
      await generateManifestPDF(manifest, false);
      onSave(manifest);
      setFormData({ ...formData, manifestNumber: '', orders: '', palletsCount: 1 });
    } catch (e) { setError("Erro ao salvar."); }
    finally { setIsGenerating(false); }
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm space-y-8">
        <div className="flex items-center gap-3 border-b border-slate-100 pb-5">
          <CheckCircle2 className="text-orange-600 shrink-0" />
          <h2 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Nova Conferência de Palete</h2>
        </div>

        {error && (
          <div className="bg-red-50 p-4 rounded-2xl flex items-center gap-3 text-red-700 text-xs font-bold border border-red-100">
            <AlertCircle size={18} /> <p>{error}</p>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="space-y-5">
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Número do Manifesto *</label>
              <input type="text" placeholder="EX: 990123" className="w-full px-5 py-4 bg-slate-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none transition-all font-black text-slate-700" value={formData.manifestNumber} onChange={e => setFormData({ ...formData, manifestNumber: e.target.value.toUpperCase() })} />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Unidade de Origem (CD) *</label>
              <select className="w-full px-5 py-4 bg-slate-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none transition-all" value={formData.cdId} onChange={e => setFormData({ ...formData, cdId: e.target.value })}>
                {cds.map(cd => <option key={cd.id} value={cd.id}>{cd.name}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Filial de Destino *</label>
              <select className="w-full px-5 py-4 bg-slate-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none transition-all" value={formData.branchId} onChange={e => setFormData({ ...formData, branchId: e.target.value })}>
                <option value="">Selecione...</option>
                {activeBranches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
              </select>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Data *</label>
                <input type="date" className="w-full px-5 py-4 bg-slate-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none" value={formData.conferenceDate} onChange={e => setFormData({ ...formData, conferenceDate: e.target.value })} />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Qtd Paletes *</label>
                <input type="number" min="1" className="w-full px-5 py-4 bg-slate-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold" value={formData.palletsCount} onChange={e => setFormData({ ...formData, palletsCount: parseInt(e.target.value) || 1 })} />
              </div>
            </div>
          </div>
          <div className="space-y-5">
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Conferente Responsável *</label>
              <select className="w-full px-5 py-4 bg-slate-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none transition-all" value={formData.checkerId} onChange={e => setFormData({ ...formData, checkerId: e.target.value })}>
                <option value="">Selecione...</option>
                {activeCheckers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Relação de Pedidos *</label>
              <textarea rows={6} placeholder="Digite os números dos pedidos separados por espaço ou vírgula..." className="w-full px-5 py-4 bg-slate-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none transition-all resize-none text-sm font-medium" value={formData.orders} onChange={e => setFormData({ ...formData, orders: e.target.value })} />
            </div>
          </div>
        </div>

        <div className="flex flex-col sm:flex-row gap-4 pt-8 border-t border-slate-100">
          <button onClick={handlePreview} disabled={isGenerating} className="flex-1 flex items-center justify-center gap-2 px-8 py-5 bg-slate-100 text-slate-600 font-black rounded-2xl hover:bg-slate-200 transition-all uppercase tracking-widest text-xs">
            {isGenerating ? <Loader2 className="animate-spin" /> : <Eye size={18} />} Visualizar PDF
          </button>
          <button onClick={handleDownload} disabled={isGenerating} className="flex-1 flex items-center justify-center gap-2 px-8 py-5 bg-orange-600 text-white font-black rounded-2xl hover:bg-orange-700 shadow-xl shadow-orange-200 transition-all uppercase tracking-widest text-xs">
            {isGenerating ? <Loader2 className="animate-spin" /> : <FileDown size={18} />} Gerar Etiquetas
          </button>
        </div>
      </div>

      {isPreviewing && previewUrl && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
          <div className="bg-white w-full max-w-5xl h-[90vh] rounded-3xl flex flex-col overflow-hidden shadow-2xl">
            <div className="p-5 border-b flex justify-between items-center bg-slate-50">
              <h3 className="font-black text-slate-800 flex items-center gap-2 uppercase tracking-widest text-xs"><Eye size={16} className="text-orange-600" /> Prévia das Etiquetas</h3>
              <button onClick={() => setIsPreviewing(false)} className="p-2 hover:bg-red-50 text-slate-400 hover:text-red-500 rounded-full transition-colors"><X size={24} /></button>
            </div>
            <div className="flex-1 bg-slate-200 p-4 flex items-center justify-center">
              <div className="w-full h-full bg-white shadow-inner rounded-xl overflow-hidden">
                <object data={previewUrl} type="application/pdf" className="w-full h-full">
                  <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-4">
                    <Printer size={48} className="text-slate-400" />
                    <a href={previewUrl} target="_blank" rel="noopener noreferrer" className="px-8 py-3 bg-orange-600 text-white rounded-2xl font-black uppercase text-xs">Abrir Documento</a>
                  </div>
                </object>
              </div>
            </div>
            <div className="p-4 bg-white border-t flex justify-end gap-3">
              <button onClick={() => setIsPreviewing(false)} className="px-8 py-3 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs">Fechar</button>
              <button onClick={() => { const link = document.createElement('a'); link.href = previewUrl; link.download = `Etiquetas_${formData.manifestNumber}.pdf`; link.click(); }} className="px-8 py-3 bg-orange-600 text-white rounded-2xl font-black uppercase text-xs shadow-lg shadow-orange-100">Download</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ManifestForm;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Truck, 
  Scan, 
  Trash2, 
  AlertCircle, 
  FileDown, 
  Eye,
  Loader2,
  X,
  ExternalLink,
  Download,
  Printer,
  Clock
} from 'lucide-react';
import { 
  Driver, 
  Vehicle, 
  Branch, 
  DistributionCenter, 
  LoadingManifest, 
  InvoiceItem 
} from '../types';
import { generateLoadingManifestPDF } from '../services/pdfGenerator';

interface LoadingManifestFormProps {
  drivers: Driver[];
  vehicles: Vehicle[];
  branches: Branch[];
  cds: DistributionCenter[];
  onSave: (m: LoadingManifest) => void;
  currentUser: { name: string; uid: string };
}

const LoadingManifestForm: React.FC<LoadingManifestFormProps> = ({ 
  drivers, 
  vehicles, 
  branches, 
  cds, 
  onSave,
  currentUser
}) => {
  const [formData, setFormData] = useState({
    manifestNumber: `MC-${Date.now().toString().substr(-6)}`,
    cdId: cds[0]?.id || '',
    branchId: '',
    driverId: '',
    vehicleId: '',
    sealNumber: '',
    deliveryDate: new Date().toISOString().split('T')[0],
    exitTime: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
  });

  const [invoices, setInvoices] = useState<InvoiceItem[]>([]);
  const [scannerInput, setScannerInput] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const scannerRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    return () => { if (previewUrl) URL.revokeObjectURL(previewUrl); };
  }, [previewUrl]);

  const activeDrivers = drivers.filter(d => d.status === 'ATIVO');
  const activeVehicles = vehicles.filter(v => v.status === 'ATIVO');
  const activeBranches = branches.filter(b => b.status === 'ATIVO');

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    const val = scannerInput.trim();
    if (val.length !== 44 || !/^\d+$/.test(val)) {
      setError("Chave de acesso inválida (44 dígitos)");
      setScannerInput('');
      return;
    }
    if (invoices.some(i => i.key === val)) {
      setError("NF já bipada.");
      setScannerInput('');
      return;
    }
    const nfNumber = val.substring(25, 34);
    setInvoices([{ key: val, number: nfNumber }, ...invoices]);
    setScannerInput('');
    scannerRef.current?.focus();
  };

  const removeInvoice = (key: string) => setInvoices(invoices.filter(i => i.key !== key));

  const validate = () => {
    if (!formData.branchId || !formData.driverId || !formData.vehicleId || !formData.exitTime) return "Preencha todos os campos obrigatórios";
    if (invoices.length === 0) return "Bipe pelo menos uma NF";
    return null;
  };

  const constructManifest = (): LoadingManifest => {
    const cd = cds.find(c => c.id === formData.cdId);
    const branch = branches.find(b => b.id === formData.branchId);
    const driver = drivers.find(d => d.id === formData.driverId);
    const vehicle = vehicles.find(v => v.id === formData.vehicleId);
    return {
      id: `lm_${Date.now()}`,
      ...formData,
      invoices,
      createdAt: new Date().toISOString(),
      createdBy: currentUser.name,
      cdName: cd?.name || '',
      branchName: branch?.name || '',
      driverName: driver?.name || '',
      vehiclePlate: vehicle?.plate || ''
    };
  };

  const handlePreview = async () => {
    const err = validate();
    if (err) { setError(err); return; }
    setError(null);
    setIsGenerating(true);
    try {
      if (previewUrl) URL.revokeObjectURL(previewUrl);
      const m = constructManifest();
      const url = await generateLoadingManifestPDF(m, true);
      setPreviewUrl(url);
    } catch (e) { setError("Erro ao gerar PDF."); }
    finally { setIsGenerating(false); }
  };

  const handleSave = async () => {
    const err = validate();
    if (err) { setError(err); return; }
    setIsGenerating(true);
    try {
      const m = constructManifest();
      await generateLoadingManifestPDF(m, false);
      onSave(m);
      setInvoices([]);
      setFormData({ ...formData, manifestNumber: `MC-${Date.now().toString().substr(-6)}`, sealNumber: '', exitTime: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }) });
    } catch (e) { setError("Erro ao salvar."); }
    finally { setIsGenerating(false); }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6">
      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-5 bg-slate-900 text-white flex items-center justify-between">
          <div className="flex items-center gap-3">
             <Truck className="text-orange-600" />
             <h2 className="font-black uppercase tracking-tighter italic">Manifesto de Embarque</h2>
          </div>
          <span className="text-[10px] font-black tracking-widest bg-orange-600 px-3 py-1 rounded-full uppercase">Expedição CD</span>
        </div>

        <div className="p-8 grid grid-cols-1 lg:grid-cols-3 gap-10">
          <div className="space-y-4 lg:col-span-1 border-r border-slate-100 pr-0 lg:pr-10">
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Filial de Destino *</label>
              <select className="w-full p-4 bg-slate-50 border-0 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none" value={formData.branchId} onChange={e => setFormData({...formData, branchId: e.target.value})}>
                <option value="">Selecione...</option>
                {activeBranches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
              </select>
            </div>
            <div className="grid grid-cols-2 gap-4">
               <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Motorista *</label>
                <select className="w-full p-4 bg-slate-50 border-0 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none" value={formData.driverId} onChange={e => setFormData({...formData, driverId: e.target.value})}>
                  <option value="">Selecione...</option>
                  {activeDrivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Veículo *</label>
                <select className="w-full p-4 bg-slate-50 border-0 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none" value={formData.vehicleId} onChange={e => setFormData({...formData, vehicleId: e.target.value})}>
                  <option value="">Selecione...</option>
                  {activeVehicles.map(v => <option key={v.id} value={v.id}>{v.plate}</option>)}
                </select>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Nº Lacre</label>
                <input type="text" className="w-full p-4 bg-slate-50 border-0 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold" value={formData.sealNumber} onChange={e => setFormData({...formData, sealNumber: e.target.value})} />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Horário de Saída *</label>
                <div className="relative">
                  <Clock className="absolute left-4 top-4 text-slate-400" size={16} />
                  <input type="time" className="w-full pl-12 p-4 bg-slate-50 border-0 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold" value={formData.exitTime} onChange={e => setFormData({...formData, exitTime: e.target.value})} />
                </div>
              </div>
            </div>
            <div className="pt-6 space-y-4">
              <button onClick={handlePreview} disabled={isGenerating} className="w-full py-4 bg-slate-100 text-slate-600 font-black rounded-2xl hover:bg-slate-200 flex items-center justify-center gap-2 uppercase tracking-widest text-xs">
                {isGenerating ? <Loader2 className="animate-spin" size={18} /> : <Eye size={18} />} Prévia PDF
              </button>
              <button onClick={handleSave} disabled={isGenerating} className="w-full py-4 bg-orange-600 text-white font-black rounded-2xl hover:bg-orange-700 shadow-xl shadow-orange-100 flex items-center justify-center gap-2 uppercase tracking-widest text-xs">
                {isGenerating ? <Loader2 className="animate-spin" size={18} /> : <FileDown size={18} />} Finalizar Manifesto
              </button>
