      <path d="M20 80 L50 40 L80 40 L50 80 Z" fill="#ea580c" />
      <path d="M20 20 L50 60 L80 60 L50 20 Z" fill="#ea580c" />
      <path d="M50 40 L80 40 L80 60 L50 60" fill="#1e293b" opacity="0.2" />
