                    <span className="text-orange-600 font-black text-2xl tracking-tighter mb-2 block">{b.code}</span>
                    <h4 className="font-black text-slate-800 uppercase tracking-tighter text-sm mb-1 leading-tight">{b.name}</h4>
                    <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{b.city} - {b.state}</p>
                    <div className="mt-6 flex justify-between items-center">
                       <span className="flex items-center gap-1 text-[8px] font-black text-green-600 uppercase tracking-widest bg-green-50 px-2 py-0.5 rounded-full"><CheckCircle2 size={10} /> Operando</span>
                       <button onClick={() => setBranches(branches.filter(x => x.id !== b.id))} className="text-slate-200 hover:text-red-500 transition-colors"><Trash2 size={16}/></button>
                    </div>
                 </div>
               ))}
            </div>
          </div>
        );

      case 'history':
        return (
          <div className="space-y-6">
             <div className="relative">
                <Search className="absolute left-4 top-3.5 text-slate-400" size={18} />
                <input className="w-full pl-12 pr-4 py-4 bg-white border-0 rounded-2xl shadow-sm focus:ring-2 focus:ring-orange-500 outline-none font-medium" placeholder="Pesquisar por número do manifesto, carga ou destino..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
             </div>
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
                  <div className="p-6 bg-slate-50 border-b font-black text-[10px] uppercase text-slate-400 tracking-widest flex items-center gap-2">
                    <PlusCircle size={14} className="text-orange-600" /> Etiquetas de Conferência
                  </div>
                  <div className="max-h-[500px] overflow-y-auto">
                    <table className="w-full text-left text-sm">
                      <thead><tr className="bg-slate-50/50 border-b text-[10px] uppercase font-black tracking-widest text-slate-400"><th className="p-4">Nº Manifesto</th><th className="p-4">Destino</th><th className="p-4 text-center">Ação</th></tr></thead>
                      <tbody className="divide-y divide-slate-100">{manifests.filter(m => m.manifestNumber.includes(searchTerm) || m.branchName.toLowerCase().includes(searchTerm.toLowerCase())).map(m => (
                        <tr key={m.id} className="hover:bg-slate-50 transition-colors">
                          <td className="p-4 font-black text-orange-600 uppercase tracking-tighter">{m.manifestNumber}</td><td className="p-4 font-bold text-slate-700 uppercase tracking-tighter">{m.branchName}</td>
                          <td className="p-4 text-center">
                             <div className="flex justify-center gap-2">
                               <button onClick={() => generateManifestPDF(m)} className="p-2 text-slate-400 hover:text-orange-600 transition-colors"><Printer size={18}/></button>
                               <button onClick={() => setManifests(manifests.filter(x => x.id !== m.id))} className="p-2 text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={18}/></button>
                             </div>
                          </td>
                        </tr>
                      ))}</tbody>
                    </table>
                  </div>
                </div>
                <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
                  <div className="p-6 bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest flex items-center gap-2">
                    <Truck size={14} className="text-orange-600" /> Manifestos de Embarque
                  </div>
                  <div className="max-h-[500px] overflow-y-auto">
                    <table className="w-full text-left text-sm">
                      <thead><tr className="bg-slate-50/50 border-b text-[10px] uppercase font-black tracking-widest text-slate-400"><th className="p-4">Nº Carga</th><th className="p-4">Placa</th><th className="p-4 text-center">Ação</th></tr></thead>
                      <tbody className="divide-y divide-slate-100">{loadingManifests.filter(m => m.manifestNumber.includes(searchTerm) || m.vehiclePlate.includes(searchTerm)).map(m => (
                        <tr key={m.id} className="hover:bg-slate-50 transition-colors">
                          <td className="p-4 font-black text-slate-800 uppercase tracking-tighter">{m.manifestNumber}</td><td className="p-4"><div className="bg-slate-100 px-2 py-1 rounded text-[11px] font-black font-mono inline-block">{m.vehiclePlate}</div></td>
                          <td className="p-4 text-center">
                             <div className="flex justify-center gap-2">
                               <button onClick={() => generateLoadingManifestPDF(m)} className="p-2 text-slate-400 hover:text-orange-600 transition-colors"><Printer size={18}/></button>
                               <button onClick={() => setLoadingManifests(loadingManifests.filter(x => x.id !== m.id))} className="p-2 text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={18}/></button>
                             </div>
                          </td>
                        </tr>
                      ))}</tbody>
                    </table>
                  </div>
                </div>
             </div>
          </div>
        );
      case 'checkers':
        return (
          <div className="space-y-6">
             <div className="flex justify-between items-center bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
              <div>
                <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Equipe de Conferência</h3>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Colaboradores ativos no CD</p>
              </div>
              <button onClick={() => setShowForm(!showForm)} className={`p-4 rounded-2xl flex items-center gap-2 font-black uppercase text-[10px] tracking-widest transition-all ${showForm ? 'bg-slate-100 text-slate-500' : 'bg-orange-600 text-white shadow-lg shadow-orange-100'}`}>
                {showForm ? <X size={18} /> : <UserCheck size={18}/>} {showForm ? 'Cancelar' : 'Novo Conferente'}
              </button>
            </div>
            {showForm && (
              <div className="p-8 bg-white border border-orange-100 rounded-3xl shadow-xl space-y-6 animate-in slide-in-from-top duration-300">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome do Conferente</label>
                    <input className="w-full p-4 bg-slate-50 border-0 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold" placeholder="Nome Completo" value={newChecker.name} onChange={e => setNewChecker({...newChecker, name: e.target.value})} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">ID Crachá / Matrícula</label>
                    <input className="w-full p-4 bg-slate-50 border-0 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-mono" placeholder="Ex: CF1001" value={newChecker.externalId} onChange={e => setNewChecker({...newChecker, externalId: e.target.value})} />
                  </div>
                </div>
                <div className="flex justify-end pt-2">
                  <button onClick={addChecker} className="px-8 py-4 bg-orange-600 text-white font-black rounded-2xl uppercase text-[10px] tracking-widest shadow-lg shadow-orange-100">Registrar Conferente</button>
                </div>
              </div>
            )}
            <div className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm">
               <table className="w-full text-left">
                  <thead className="bg-slate-50 text-[10px] font-black uppercase text-slate-400 border-b tracking-widest"><tr><th className="p-6">Nome</th><th className="p-6">ID Matrícula</th><th className="p-6 text-center">Ação</th></tr></thead>
                  <tbody className="divide-y divide-slate-100">{checkers.map(c => <tr key={c.id} className="hover:bg-slate-50 transition-colors"><td className="p-6 font-black text-slate-800 uppercase tracking-tighter text-sm">{c.name}</td><td className="p-6 text-slate-500 font-mono text-sm tracking-widest">{c.externalId}</td><td className="p-6 text-center"><button onClick={() => setCheckers(checkers.filter(x => x.id !== c.id))} className="text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={20}/></button></td></tr>)}</tbody>
               </table>
            </div>
          </div>
        );
      default: return <Dashboard manifests={manifests} />;
    }
  };

  return (
    <Layout user={user} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout}>
      {renderContent()}
    </Layout>
  );
};

export default App;
